(function(w){w.__PC_DUOC_CHUNKS=w.__PC_DUOC_CHUNKS||{};w.__PC_DUOC_CHUNKS["jci-07"]=[{"c":"PCC.02.00","ch":"PCC","t":"Bệnh nhân và gia đình tham gia vào mọi khía cạnh chăm sóc, điều trị và dịch vụ của họ.","p":"Bệnh nhân tham gia vào việc chăm sóc sức khỏe của họ có thể đưa ra quyết định hợp tác tốt hơn với các nhà cung cấp dịch vụ\nchăm sóc sức khỏe của họ. Điều này dẫn đến kết quả điều trị bệnh nhân được cải thiện. Việc kích hoạt và tham gia hiệu quả của\nbệnh nhân cho phép bệnh nhân tích cực tham gia vào việc chăm sóc sức khỏe của họ bằng cách hợp tác với các nhà cung cấp dịch\nvụ chăm sóc sức khỏe của họ. Các ví dụ về sự tham gia của bệnh nhân bao gồm:\n• Tham gia vào các quyết định về việc chăm sóc (chấp nhận và từ chối điều trị)\n• Đặt câu hỏi và tìm kiếm thông tin về việc chăm sóc\n• Yêu cầu ý kiến thứ hai\n\nPatIent-Centered Care\n\nPatient-Centered\nBệnh nhân và gia đình cần thông tin về tình trạng sức khỏe của họ để tham gia vào việc đưa ra quyết định về\nviệc chăm sóc và tự chăm sóc sau khi xuất viện. Các nhà cung cấp dịch vụ chăm sóc sức khỏe thông báo cho\nbệnh nhân về các phát hiện đánh giá và chẩn đoán, chẩn đoán và dịch vụ chăm sóc và điều trị được đề xuất.\n\nBệnh nhân có quyền được thông báo về kết quả mong đợi của việc chăm sóc và điều trị theo kế hoạch. Bệnh nhân\ncũng phải được thông báo khi có sự kiện hoặc kết quả không lường trước xảy ra trong quá trình chăm sóc hoặc điều\ntrị của họ. Ví dụ về các sự kiện không lường trước bao gồm:\n• Nhiễm trùng mắc phải tại bệnh viện\n• Lỗi dùng thuốc\n• Loét do tì đè\n• Nhiễm trùng sau phẫu thuật\nRõ ràng ai sẽ cung cấp cho bệnh nhân thông tin về việc chăm sóc của họ, bao gồm:\n• Tình trạng bệnh lý\n• Chăm sóc và điều trị theo kế hoạch\n• Kết quả mong đợi\n• Sự kiện không lường trước\nBệnh nhân và gia đình hiểu các quyết định được đưa ra về việc chăm sóc của họ và cách tham gia vào các quyết định\nđó. Không phải tất cả bệnh nhân đều muốn biết chẩn đoán và tiên lượng đã xác nhận hoặc muốn tham gia vào các\nquyết định liên quan đến việc chăm sóc của họ. Những bệnh nhân này được cung cấp tùy chọn để những người\nkhác tham gia vào quá trình ra quyết định về việc chăm sóc của họ.\nBệnh viện có chính sách về quy trình tìm kiếm ý kiến thứ hai. Bệnh viện không được cấm, ngăn cản hoặc cản trở nỗ\nlực tìm kiếm ý kiến thứ hai của bệnh nhân. Bệnh viện tham gia vào việc xin ý kiến thứ hai bằng cách cung cấp cho\nbệnh nhân hoặc nhà cung cấp dịch vụ chăm sóc sức khỏe khác thông tin về tình trạng của bệnh nhân. Bệnh viện\nkhông được giữ lại bất kỳ thông tin nào được yêu cầu xin ý kiến thứ hai. Bệnh viện không được yêu cầu trả tiền cho\ný kiến thứ hai khi bệnh nhân yêu cầu.\nBệnh nhân có thể chỉ định người khác nhận thông tin cùng hoặc thay mặt họ theo luật pháp và quy định. Bệnh nhân\ncũng có thể cho phép người này đưa ra quyết định và đồng ý chăm sóc thay mặt họ. Các ví dụ bao gồm:\n• Thành viên gia đình\n• Vợ/chồng hoặc bạn đời\n• Người chăm sóc\n• Bạn bè\n• Người thay thế ra quyết định\nThông tin trong chính sách về việc xin ý kiến thứ hai có thể bao gồm những thông tin sau:\n• Quy trình thu thập và chia sẻ thông tin bệnh nhân cần thiết cho ý kiến thứ hai\n• Có cần phải có sự đồng ý bổ sung để tiết lộ thông tin bệnh nhân để chia sẻ thông tin cho ý kiến thứ hai hay không\n• Ai chịu trách nhiệm tạo điều kiện cho yêu cầu và bất kỳ thông tin liên lạc nào liên quan đến việc xin ý kiến thứ hai\n• Bất kỳ thông tin nào về các khoản thanh toán bổ sung liên quan đến việc xin ý kiến thứ hai\nCác yếu tố đo lường được của PCC.02.00\n1.\nBệnh viện hỗ trợ và thúc đẩy sự tham gia của bệnh nhân và gia đình vào các quy trình chăm sóc\nvà ra quyết định.\n2. Nhóm chăm sóc sức khỏe thông báo cho bệnh nhân và gia đình về tình trạng bệnh lý, bất kỳ chẩn\nđoán nào đã được xác nhận, tiên lượng và kế hoạch chăm sóc và điều trị để khuyến khích sự\ntham gia và hợp tác của bệnh nhân. (Xem thêm PCC.03.00, ME 1)\n3. Bệnh nhân được thông báo về bất kỳ kết quả không lường trước nào xảy ra trong quá trình chăm\nsóc và điều trị của họ. (Xem thêm MMU.07.00, ME 1)\n4. Bệnh viện cho phép bệnh nhân tìm kiếm ý kiến thứ hai mà không ảnh hưởng đến việc chăm sóc\nbệnh nhân.\n\nPatIent-Centered Care\n\nPatient-Centered","m":[],"sec":"Trải nghiệm của bệnh nhân"},{"c":"PCC.02.01","ch":"PCC","t":"Bệnh viện thông báo cho bệnh nhân và gia đình về quyền và trách nhiệm của họ trong việc từ chối hoặc ngừng điều trị, ngừng các dịch vụ hồi sức và từ bỏ hoặc rút các phương pháp điều trị duy trì sự sống.","p":"Bệnh viện tôn trọng quyền của bệnh nhân trong việc đưa ra quyết định về việc ngừng, từ chối, tạm dừng hoặc từ bỏ\ncác phương pháp điều trị duy trì sự sống. Có các quy trình để giáo dục bệnh nhân và gia đình của họ về các kết quả\ntiềm ẩn của những quyết định này và trách nhiệm của bệnh viện liên quan đến các quyết định này. Bệnh nhân hoặc\nnhững người đưa ra quyết định thay mặt cho họ có thể quyết định không tiếp tục chăm sóc hoặc điều trị theo kế\nhoạch hoặc ngừng điều trị sau khi đã bắt đầu. (Không bao giờ được ngừng chăm sóc và bác sĩ cũng không được gợi ý\nrằng nên ngừng.) Một số quyết định khó khăn nhất liên quan đến việc tạm dừng các dịch vụ hồi sức hoặc rút các\ndịch vụ duy trì sự sống.\nVì những loại quyết định này rất phức tạp nên bệnh viện xây dựng một khuôn khổ để hướng dẫn quá trình ra quyết\nđịnh này. Khuôn khổ này thực hiện các mục đích sau:\n•\nGiúp bệnh viện xác định vị trí của mình về các vấn đề này.\n•\nĐảm bảo rằng vị trí của bệnh viện phù hợp với các chuẩn mực tôn giáo và văn hóa của cộng đồng và với bất\nkỳ yêu cầu pháp lý hoặc quy định nào, đặc biệt là khi các yêu cầu pháp lý về hồi sức không phù hợp với mong\nmuốn của bệnh nhân.\n•\nXử lý các tình huống mà những quyết định này được thay đổi trong quá trình chăm sóc.\n•\nHướng dẫn các bác sĩ chăm sóc sức khỏe thông qua các vấn đề về đạo đức và pháp lý trong việc thực hiện\nmong muốn của bệnh nhân.\nBệnh viện xây dựng các chính sách và quy trình để đảm bảo tính nhất quán của quy trình ra quyết định liên quan đến\nmong muốn của bệnh nhân. Việc xây dựng các chính sách và quy trình này liên quan đến nhiều chuyên gia và quan\nđiểm. Các chính sách và quy trình xác định các ranh giới trách nhiệm và cách thức quy trình được ghi lại trong hồ sơ\ny tế của bệnh nhân.\nBệnh viện thông báo cho bệnh nhân và gia đình về quyền đưa ra những quyết định này, kết quả tiềm năng của\nnhững quyết định này và trách nhiệm của bệnh viện liên quan đến những quyết định đó. Bệnh nhân và gia đình\nđược thông báo về bất kỳ phương án chăm sóc và điều trị nào.\nCác yếu tố đo lường được của PCC.02.01\n1.\nBệnh viện xác định vị trí của mình trong việc từ chối các dịch vụ hồi sức và từ bỏ hoặc rút lại các phương\npháp điều trị duy trì sự sống.\n2.\nVị trí của bệnh viện phù hợp với các chuẩn mực tôn giáo và văn hóa của cộng đồng và bất kỳ yêu cầu pháp lý\nhoặc quy định nào.\n3.\nBệnh viện thông báo cho bệnh nhân và gia đình về quyền từ chối hoặc ngừng điều trị của họ và trách nhiệm\ncủa bệnh viện liên quan đến các quyết định này.\n4.\nBệnh viện thông báo cho bệnh nhân về hậu quả của các quyết định của họ.\n5.\nBệnh viện thông báo cho bệnh nhân về các phương án chăm sóc và điều trị khả dụng.\n6.\nBệnh viện cung cấp cho các bác sĩ chăm sóc sức khỏe các nguồn lực liên quan đến các cân nhắc về đạo đức và\npháp lý trong việc thực hiện mong muốn của bệnh nhân.","m":[],"sec":"Trải nghiệm của bệnh nhân"},{"c":"PCC.02.02","ch":"PCC","t":"Bệnh viện đánh giá dữ liệu về trải nghiệm của bệnh nhân và thực hiện các cải tiến để nâng cao chất lượng chăm sóc bệnh nhân.","p":"Đánh giá trải nghiệm của bệnh nhân và các yếu tố khác trong việc chăm sóc bệnh nhân cung cấp thông tin đầy\nđủ hơn về chất lượng của họ. Thông tin này có thể được sử dụng để xác định xem bệnh nhân có hài lòng với\ndịch vụ chăm sóc mà họ đang nhận được hay không và có thể được sử dụng để hướng dẫn cải thiện trong toàn\nbệnh viện.\n\nPatIent-Centered Care\n\nPatient-Centered\nTrải nghiệm của bệnh nhân bao gồm nhiều tương tác diễn ra với mọi loại nhân viên—bao gồm bác sĩ, y tá, các\nchuyên gia khác và nhân viên hỗ trợ—cũng như dịch vụ chăm sóc, điều trị và dịch vụ mà họ nhận được trong\ncác lần gặp gỡ chăm sóc sức khỏe. Một thành phần quan trọng của dịch vụ chăm sóc lấy bệnh nhân làm trung\ntâm là hiểu được trải nghiệm của bệnh nhân.\n\nViệc thu thập và phân tích thông tin về trải nghiệm của bệnh nhân có thể được sử dụng để giúp xác định\nxem liệu dịch vụ chăm sóc mà bệnh nhân đang nhận được có đáp ứng được sở thích, nhu cầu và giá trị của\ntừng bệnh nhân hay không. Bệnh viện đã thiết lập một quy trình để thu thập và phân tích trải nghiệm của\nbệnh nhân như một phần của việc đo lường chất lượng chăm sóc bệnh nhân và có khả năng cải thiện kết\nquả của bệnh nhân.\nTrải nghiệm của bệnh nhân là một biện pháp khách quan, bao gồm một số khía cạnh của việc cung cấp dịch\nvụ chăm sóc sức khỏe. Bệnh nhân cân nhắc thông tin này khi đưa ra quyết định về nơi cung cấp dịch vụ\nchăm sóc sức khỏe. Sự hài lòng của bệnh nhân là thước đo chủ quan về nhận thức của bệnh nhân về một\ndịch vụ so với kỳ vọng của họ. Cả hai đều quan trọng trong việc hiểu quan điểm của bệnh nhân về dịch vụ\nchăm sóc của họ.\nVí dụ về các biện pháp đo lường trải nghiệm khách quan của bệnh nhân bao gồm:\n• Bệnh nhân có quyền truy cập vào dữ liệu chăm sóc sức khỏe của họ không\n• Thời gian chờ đợi khi cố gắng lên lịch hẹn\n• Bệnh nhân có đồng ý rằng nhóm chăm sóc sức khỏe của họ đã trả lời tất cả các câu hỏi của họ về việc chăm\nsóc họ không\nVí dụ về các biện pháp đo lường sự hài lòng của bệnh nhân chủ quan bao gồm:\n• Bệnh nhân có hài lòng với cách bố trí phòng không\n• Bệnh nhân có thấy rằng các nhân viên đã phản hồi nhu cầu của họ kịp thời không\n• Bệnh nhân có cảm thấy an toàn trong bệnh viện không\nCác biện pháp đo lường sự hài lòng của bệnh nhân có tác động đến việc chăm sóc bệnh nhân có thể được sử\ndụng để thu thập dữ liệu trải nghiệm ban đầu của bệnh nhân và đáp ứng các kỳ vọng của tiêu chuẩn này.\nTuy nhiên, các nhà lãnh đạo bệnh viện nên cập nhật các biện pháp thu thập dữ liệu để cuối cùng xác định\nthông tin về trải nghiệm của bệnh nhân nhằm cải thiện có ý nghĩa.\nCác yếu tố đo lường được của PCC.02.02\n1. Lãnh đạo bệnh viện triển khai quy trình thu thập và đánh giá trải nghiệm của bệnh nhân.\n2. Dữ liệu từ trải nghiệm của bệnh nhân được thu thập, tổng hợp, phân tích và chuyển đổi thành\nthông tin để xác định và triển khai các chiến lược cải thiện trải nghiệm của bệnh nhân. (Xem thêm\nQPS.03.00, ME 2)\n3. Lãnh đạo bệnh viện xác định các lĩnh vực ưu tiên để cải thiện trải nghiệm của bệnh nhân, từ đó tác\nđộng tích cực đến việc chăm sóc bệnh nhân.\n4. D Dữ liệu được thu thập và phân tích sau khi cải thiện trải nghiệm của bệnh nhân để đánh giá tác\nđộng của chúng đến chất lượng chăm sóc bệnh nhân.","m":[],"sec":"Trải nghiệm của bệnh nhân"},{"c":"PCC.02.03","ch":"PCC","t":"Bệnh viện thông báo cho bệnh nhân và gia đình về quyền khiếu nại và được thông báo về các lỗi liên quan đến việc chăm sóc của họ và quy trình xử lý của bệnh viện đối với các lỗi đó.","p":"Bệnh nhân có quyền báo cáo khiếu nại về việc chăm sóc của họ và được xem xét những khiếu nại đó và nếu có thể,\nđược giải quyết. Bệnh nhân cũng có quyền được thông báo về những sai sót trong việc chăm sóc của họ. Các quy trình\nhiệu quả để giải quyết những vấn đề này có thể cải thiện chất lượng chăm sóc được cung cấp. Các quyết định về việc\nchăm sóc bệnh nhân đôi khi dẫn đến những câu hỏi, xung đột hoặc những tình huống khó xử khác cho bệnh viện và\nbệnh nhân, gia đình hoặc những người ra quyết định khác. Những tình huống khó xử này có thể phát sinh từ các quyết\nđịnh liên quan đến việc tiếp cận, điều trị hoặc xuất viện. Chúng có thể đặc biệt khó giải quyết khi các quyết định phức\ntạp hoặc liên quan đến các cân nhắc về mặt đạo đức. Ví dụ, từ chối các dịch vụ hồi sức, từ bỏ hoặc rút lại phương pháp\nđiều trị duy trì sự sống hoặc xác định nơi xuất viện cho một bệnh nhân có nhu cầu chăm sóc phức tạp.\n\nPatIent-Centered Care\n\nBệnh viện có các quy trình để điều tra và giải quyết khiếu nại trong một khung thời gian xác định. Bệnh viện xây dựng các\nchính sách chỉ rõ những ai cần tham gia vào các quy trình và cách bệnh nhân và gia đình tham gia.\n\nBệnh viện có quy trình tiết lộ lỗi cho bệnh nhân và gia đình của họ, và một chính sách mô tả quy trình này. Bệnh viện có\ntrách nhiệm tiết lộ và giải quyết lỗi trong khi chăm sóc bệnh nhân. Việc tiết lộ lỗi kịp thời sẽ khuyến khích việc điều tra\nnhanh chóng để giảm thiểu khả năng xảy ra lỗi tương tự, giảm khả năng kiện tụng và giúp duy trì lòng tin giữa bệnh nhân\nvà nhóm chăm sóc của họ. Ví dụ về lỗi bao gồm:\n• Dùng sai thuốc cho bệnh nhân\n• Thực hiện xét nghiệm chẩn đoán sai cho bệnh nhân\n• Phẫu thuật sai vị trí cho bệnh nhân\n• Cung cấp dịch vụ chăm sóc hoặc điều trị mà không có sự đồng ý khi cần thiết\n\nQuy trình tiết lộ lỗi cho bệnh nhân tuân thủ theo luật pháp và quy định của địa phương. Quy trình báo cáo khiếu nại có thể\nbao gồm những nội dung sau:\n• Một số điện thoại chuyên dụng để báo cáo khiếu nại\n• Một biểu mẫu web hoặc biểu mẫu giấy có thể nộp cho bệnh viện\n• Một người được chỉ định để xem xét khiếu nại của bệnh nhân\n• Một khung thời gian xác định để giải quyết khiếu nại\n• Hướng dẫn về cách đưa bệnh nhân và gia đình họ vào quy trình giải quyết khiếu nại\n\nBệnh viện xây dựng chính sách giải quyết vấn đề tiết lộ lỗi lâm sàng cho bệnh nhân và quy trình tiết lộ lỗi được xây dựng\ntheo luật pháp và quy định của địa phương. Quy trình này bao gồm những nội dung sau:\n• Tiết lộ lỗi kịp thời\n• Xin lỗi về lỗi\n• Mô tả cách xảy ra lỗi\n• Mô tả cách chăm sóc bệnh nhân và thời gian lưu trú có thể bị ảnh hưởng bởi lỗi\n• Thảo luận về cách bệnh viện ngăn ngừa lỗi xảy ra lần nữa\n\nCác yếu tố đo lường được của PCC.02.03\n1.\nBệnh nhân và gia đình được thông báo về quy trình báo cáo khiếu nại. (Xem thêm APR.09.00, MEs 1 và 2)\n2. Bệnh viện điều tra và, khi có thể, giải quyết khiếu nại trong khung thời gian được xác định trong chính sách\ncủa bệnh viện. Nếu khiếu nại không thể được giải quyết ngay lập tức, bệnh viện sẽ xác nhận đã nhận\nđược khiếu nại và thông báo cho bệnh nhân về việc theo dõi khiếu nại.\n3. Bệnh viện xây dựng chính sách bằng văn bản giải quyết việc tiết lộ lỗi lâm sàng cho bệnh nhân, bao gồm tối\nthiểu những nội dung sau:\n• Bệnh viện định nghĩa lỗi lâm sàng như thế nào\n• Các trường hợp khuyến nghị tiết lộ lỗi lâm sàng\n• Ai chịu trách nhiệm thông báo cho bệnh nhân về lỗi lâm sàng\n• Các cá nhân hoặc tổ chức khác phải được thông báo khi có thể\n4. Bệnh viện thực hiện và tuân thủ chính sách của mình về việc tiết lộ lỗi lâm sàng.\n5. Bệnh viện tuân thủ quy trình nội bộ để phân tích lỗi lâm sàng và ngăn ngừa lỗi xảy ra lần nữa.\n\nPatIent-Centered Care\n\nPatient-Centered\n\nQuy trình đồng ý của bệnh nhân","m":[],"sec":"Trải nghiệm của bệnh nhân"},{"c":"PCC.03.00","ch":"PCC","t":"Sự đồng ý được thông báo được lấy thông qua một quy trình do bệnh viện xác định và được thực hiện bởi nhân viên được đào tạo theo cách thức và ngôn ngữ mà bệnh nhân hoặc người đại diện của họ có thể hiểu được.","p":"Sự đồng ý có thông tin là rất quan trọng đối với việc chăm sóc bệnh nhân chất lượng cao, vì nó đảm bảo rằng\nbệnh nhân hiểu được các rủi ro và lợi ích tiềm ẩn, cũng như các phương án thay thế. Quy trình đồng ý có thông\ntin tôn trọng quyền tự chủ và khả năng ra quyết định của bệnh nhân. Một trong những cách chính mà bệnh nhân\ntham gia vào các quyết định chăm sóc của họ là thông qua việc đồng ý có thông tin. Để đồng ý, bệnh nhân phải\nđược thông báo về những yếu tố cần thiết để đưa ra quyết định có thông tin.\nQuy trình đồng ý được bệnh viện xác định rõ ràng trong các chính sách và thủ tục và bao gồm các yêu cầu về tài\nliệu. Các luật và quy định có liên quan được đưa vào các chính sách và thủ tục. Sự đồng ý có thông tin có thể được\nyêu cầu nhiều lần trong suốt quá trình chăm sóc. Bệnh nhân và gia đình được thông báo về các xét nghiệm, thủ\nthuật và phương pháp điều trị nào cần có sự đồng ý và cách họ có thể đồng ý; ví dụ, đồng ý bằng lời nói hoặc ký\nvào mẫu đồng ý.\nBệnh nhân hiểu ai có thể cung cấp sự đồng ý có thông tin ngoài bệnh nhân, nếu có thể thông qua luật pháp, quy\nđịnh hoặc văn hóa. Các nhân viên được chỉ định được đào tạo về quy trình đồng ý có thông tin. Giáo dục được\ncung cấp cho bệnh nhân và gia đình như một phần của quy trình lấy sự đồng ý có thông tin để điều trị và được\ncung cấp bằng ngôn ngữ và cách thức mà bệnh nhân hiểu.\nBệnh viện xác định những tình huống mà người ra quyết định thay thế có thể tham gia vào các quyết định về việc\nchăm sóc bệnh nhân. Điều này đặc biệt đúng khi bệnh nhân không có khả năng về tinh thần hoặc thể chất để đưa\nra quyết định, khi văn hóa hoặc phong tục yêu cầu người khác đưa ra quyết định hoặc khi bệnh nhân là trẻ em.\nKhi bệnh nhân không thể đưa ra quyết định về việc chăm sóc của mình, người ra quyết định thay thế sẽ được xác\nđịnh.\nĐồng ý có thông tin là một quy trình. Quy trình này phải phù hợp với luật pháp và quy định của địa phương cũng\nnhư các chuẩn mực nghề nghiệp. Quy trình này có thể diễn ra qua nhiều cuộc trò chuyện. Tóm tắt các cuộc trò\nchuyện này phải được ghi lại theo chính sách của bệnh viện.\nBệnh viện xác định thông tin nào phải được ghi lại như một phần của quy trình đồng ý trong chính sách của\nmình;\ncác yếu tố chung trong yêu cầu về tài liệu bao gồm:\n• Tên bệnh viện\n• Tên xét nghiệm, thủ thuật hoặc phương pháp điều trị được bao gồm trong bản đồng ý có thông tin\n• Tên của bác sĩ chịu trách nhiệm thực hiện các thủ thuật\n• Chữ ký của bệnh nhân hoặc người được chỉ định nếu bệnh viện hoặc luật pháp và quy định yêu cầu phải có\nmẫu đồng ý có chữ ký\n• Ngày và giờ bệnh nhân đồng ý\n• Tuyên bố rằng thủ thuật đã được giải thích cho bệnh nhân hoặc người được chỉ định, bao gồm các lợi ích, rủi\nro và\ncác phương án thay thế\n• Khả năng thành công, các biến chứng tiềm ẩn, quá trình phục hồi và các kết quả có thể xảy ra của\nviệc không điều trị\n• Tên, chữ ký và vai trò của người đã giải thích thủ thuật cho bệnh nhân hoặc người thay thế\n• Tên, chữ ký và vai trò của nhân viên lâm sàng chứng kiến sự đồng ý nếu cần\n\nBệnh viện xác định các yêu cầu và quy trình cấp đồng ý khẩn cấp hoặc khi bỏ qua quy trình đồng ý có thông tin là\ncó thể chấp nhận được. Điều này có thể bao gồm các nội dung sau:\n•\nNhững tình huống nào sẽ cần sự đồng ý khẩn cấp hoặc bỏ qua quy trình đồng ý có thông tin (ví dụ: để\ncung cấp phương pháp điều trị cứu sống cho bệnh nhân bất tỉnh, không có thông tin nhận dạng hoặc\nliên lạc, khi không thể liên lạc với người thay thế hoặc người giám hộ của trẻ vị thành niên).\n\nPatIent-Centered Care\n\nPatient-Centered\n\n•\nAi được phép cấp sự đồng ý khẩn cấp hoặc quyết định thời điểm bỏ qua quy trình đồng ý có\nthông tin\n•\nCách thông báo cho bệnh nhân hoặc người được chỉ định về quyết định cấp phép khẩn cấp\nhoặc bỏ qua quy trình đồng ý có thông tin\n\nKhi cần có sự đồng ý được thông báo, phải có được sự đồng ý được thông báo và ghi lại trước khi bắt đầu điều\ntrị hoặc thủ thuật, trừ trường hợp khẩn cấp.\n\nBệnh viện xác định rõ ràng các yêu cầu về tài liệu trong chính sách đồng ý được thông báo của mình. Ngoại trừ\ntrường hợp khẩn cấp, bệnh viện sẽ yêu cầu mẫu đơn đồng ý được thông báo có chữ ký của bệnh nhân hoặc\nngười thay thế theo luật pháp và quy định của địa phương. Tuy nhiên, tất cả các bệnh viện phải xác định rõ ràng\nthông tin nào là bắt buộc và cách thức ghi chép; tài liệu phải phù hợp với chính sách của bệnh viện. Yêu cầu về tài\nliệu có thể bao gồm những nội dung sau:\n• Quy trình đồng ý thông báo được ghi lại ở đâu và như thế nào trong hồ sơ y tế của bệnh nhân (ví dụ: trên\nmẫu đơn đồng ý hoặc trong ghi chú tiến trình)\n• Ngày và giờ ghi chép\n• Thông tin được thảo luận với bệnh nhân hoặc người được chỉ định của họ như một phần của quy trình đồng ý\nthông báo (ví dụ: tên của quy trình hoặc phương pháp điều trị, các phương pháp điều trị thay thế, rủi ro và lợi ích\ncủa quy trình hoặc phương pháp điều trị được đề xuất, kết quả mong đợi và các biến chứng thường gặp của quy\ntrình hoặc phương pháp điều trị)\n• Tên, chữ ký và vai trò của nhân viên lâm sàng cung cấp thông tin cho và nhận được sự đồng ý từ bệnh nhân\nhoặc người được chỉ định của họ\n• Tên và chữ ký của bệnh nhân hoặc người được chỉ định chấp thuận\n\nCác yếu tố đo lường được của PCC.03.00\n1. Bệnh viện xây dựng chính sách bằng văn bản và thực hiện quy trình đồng ý có thông tin bao gồm ít nhất\nnhững nội dung sau:\n• Xác định thông tin nào phải được thảo luận và ghi chép lại như một phần của quy trình đồng ý\n• Xác định các tình huống mà người ra quyết định thay thế là cần thiết hoặc được phép và ai ngoài bệnh nhân\ncó thể đồng ý, theo luật pháp và quy định\n• Quy định rằng ngày và giờ phải được ghi chép lại như một phần của quy trình đồng ý\n• Xác định và đào tạo nhân viên được phép lấy đồng ý có thông tin\n• Mô tả quy trình và các yêu cầu để lấy đồng ý khẩn cấp hoặc bỏ qua quy trình đồng ý có thông tin\n• Ghi chép các yêu cầu để lấy đồng ý có thông tin qua điện thoại nếu được phép\n(Xem thêm ACC.02.01, ME 5; COP.09.06, ME 1; COP.10.01, ME 1; PCC.02.00, ME 2)\n2. D Chính sách của bệnh viện xác định những xét nghiệm, quy trình và phương pháp điều trị nào cần có sự\nđồng ý, bao gồm tối thiểu những nội dung sau:\n• Phẫu thuật\n• Gây mê và an thần\n• Sử dụng máu và các sản phẩm máu\n• Các thủ thuật và phương pháp điều trị có nguy cơ cao khác do bệnh viện xác định (Xem thêm ASC.02.03,\nME 1; COP.09.06, ME 1; COP.10.01, ME 1; IPSG.04.00, ME 1)\n3. Quy trình đồng ý có thông tin và giáo dục liên quan được cung cấp theo cách thức và ngôn ngữ mà bệnh\nnhân hoặc người ra quyết định thay thế hiểu được. (Xem thêm ACC.02.01, ME 4)\n4. Sự đồng ý có thông tin được lấy theo cách thức phù hợp với quy trình được nêu trong chính sách của bệnh\nviện.\n\nPatIent-Centered Care\n\nPatient-Centered\n\nGiáo dục bệnh nhân và gia đình","m":[],"sec":"Quy trình đồng ý của bệnh nhân"},{"c":"PCC.04.00","ch":"PCC","t":"Bệnh viện cung cấp chương trình giáo dục dựa trên việc chăm sóc, điều trị và các dịch vụ mà bệnh viện cung cấp và đáp ứng nhu cầu của nhóm bệnh nhân mà bệnh viện phục vụ.","p":"Giáo dục bệnh nhân thúc đẩy sự tham gia của bệnh nhân và dẫn đến kết quả cải thiện, bao gồm cả việc tuân thủ tốt\nhơn đối với thuốc và phương pháp điều trị. Bệnh viện xây dựng chương trình giáo dục dựa trên các dịch vụ được\ncung cấp và nhu cầu của nhóm bệnh nhân. Bệnh viện lựa chọn cách thức tổ chức chương trình và cách phân bổ\nnguồn lực.\n\nĐội ngũ nhân viên lâm sàng hợp tác để phát triển tài liệu giáo dục bệnh nhân. Sự hợp tác này dẫn đến giáo dục bệnh\nnhân toàn diện hơn, nhất quán hơn và hiệu quả hơn. Những người chịu trách nhiệm cung cấp giáo dục bệnh nhân\ncó kiến thức, nguồn lực và kỹ năng giao tiếp để thực hiện việc đó. Bệnh viện quyết định cách giám sát chương trình\ngiáo dục. Ví dụ về giám sát bao gồm điều phối viên giáo dục, ủy ban hoặc dịch vụ.\n\nBệnh viện đảm bảo rằng những người cung cấp giáo dục có nguồn lực để thực hiện. Điều này có thể bao gồm\nnhững điều sau:\n•\nCung cấp đào tạo về cách cung cấp giáo dục bệnh nhân hiệu quả\n•\nPhân công nhân viên lâm sàng có nền tảng giáo dục hoặc lâm sàng phù hợp về chủ đề này\n•\nCung cấp nguồn lực cho bệnh nhân (ví dụ: video giáo dục theo yêu cầu, tài liệu viết, bài tập thực hành, tài liệu\nhướng dẫn cách sử dụng công nghệ hoặc thiết bị mới sau khi xuất viện)\n•\nĐảm bảo quyền truy cập vào dịch vụ biên dịch\n\nCác yếu tố đo lường được của PCC.04.00\n1.\nBệnh viện lập kế hoạch giáo dục dựa trên việc chăm sóc, điều trị và các dịch vụ được cung cấp cũng như\nnhu cầu của nhóm bệnh nhân. (Xem thêm ASC.02.03, ME 2; ASC.03.01, ME 2; HCT.01.01, ME 4)\n2. Bệnh viện có chương trình giáo dục bệnh nhân trong toàn bệnh viện bao gồm các nội dung sau:\n• Giám sát bởi một hoặc nhiều thành viên đủ tiêu chuẩn của đội ngũ nhân viên lâm sàng\n• Tiếp cận các nguồn tài nguyên giáo dục dựa trên việc chăm sóc, điều trị và các dịch vụ được cung cấp cũng\nnhư nhu cầu của nhóm bệnh nhân\n3. Giáo dục bệnh nhân và gia đình được phát triển và thực hiện thông qua sự hợp tác giữa các thành viên của\nđội ngũ nhân viên liên ngành.\n4. Đội ngũ nhân viên lâm sàng cung cấp giáo dục có kiến thức chuyên môn và kỹ năng giao tiếp để thực hiện.","m":[],"sec":"Giáo dục bệnh nhân và gia đình"},{"c":"PCC.04.01","ch":"PCC","t":"Nhu cầu giáo dục và khả năng học tập của mỗi bệnh nhân được đánh giá và ghi lại trong hồ sơ y tế của họ.","p":"Nhân viên lâm sàng phải hiểu được nhu cầu giáo dục riêng biệt và khả năng học tập của từng bệnh nhân để\ncung cấp giáo dục hiệu quả. Giáo dục tập trung vào kiến thức và kỹ năng cụ thể mà bệnh nhân sẽ cần để đưa\nra quyết định chăm sóc, tham gia vào việc chăm sóc của họ và tiếp tục chăm sóc tại nhà hoặc cấp độ chăm sóc\ntiếp theo.\n\nNhu cầu giáo dục cá nhân của bệnh nhân dựa trên việc chăm sóc và điều trị của bệnh nhân. Nhu cầu giáo dục\nđược ghi lại trong hồ sơ y tế của bệnh nhân trong suốt quá trình chăm sóc khi nhu cầu được xác định hoặc\nthay đổi. Việc ghi lại những nhu cầu này giúp nhóm chăm sóc bệnh nhân dễ dàng tham gia vào quá trình giáo\ndục hơn. Nhu cầu giáo dục bao gồm những điều sau:\n\nPatIent-Centered Care\n\nPatient-Centered\n• Ngôn ngữ ưa thích của bệnh nhân để nói hoặc viết thông tin\n• Cách bệnh nhân ưa thích để tiếp nhận thông tin (ví dụ: video, bản trình diễn, tài liệu viết)\n• Sự tham gia của một người học bổ sung (ví dụ, phụ huynh, y tá chăm sóc tại nhà)\n\nCó nhiều biến số của bệnh nhân quyết định xem bệnh nhân và gia đình có sẵn lòng và có khả năng học hay không. Đội ngũ\nnhân viên lâm sàng có trình độ đánh giá bệnh nhân và gia đình họ về bất kỳ nhu cầu học tập hoặc rào cản nào và mức độ sẵn\nsàng học tập. Bệnh nhân và gia đình có thể bị ảnh hưởng bởi các rào cản học tập. Ví dụ về các rào cản bao gồm:\n•\nTrình độ học vấn\n•\nNgôn ngữ\n•\nĐộng lực\n•\nKhiếm thị hoặc khiếm thính\n•\nRối loạn học tập\n\nBệnh nhân và gia đình được cung cấp giáo dục trong suốt quá trình chăm sóc và được ghi lại trong hồ sơ y tế của bệnh\nnhân. Ví dụ về thời điểm giáo dục diễn ra và được ghi lại bao gồm:\n•\nLà một phần của quá trình xin sự đồng ý có hiểu biết để điều trị\n•\nKhi bệnh nhân dự kiến được xuất viện về nhà với thiết bị y tế hoặc băng bó vết thương\n•\nKhi bắt đầu chế độ ăn uống hoặc dùng thuốc tại nhà mới\n\nMỗi bệnh viện quyết định các yêu cầu về tài liệu để đánh giá giáo dục, lập kế hoạch và cung cấp giáo dục cho bệnh nhân.\n\nBệnh nhân và gia đình được khuyến khích tham gia vào quá trình chăm sóc và đặt câu hỏi. Bệnh viện có quy trình để xác\nminh rằng bệnh nhân và gia đình họ hiểu được nội dung giáo dục mà họ đã nhận được, chẳng hạn như sử dụng phương\npháp “dạy lại”.\nCác yếu tố đo lường được của PCC.04.01\n1.\nNhu cầu và sở thích giáo dục của từng bệnh nhân và, khi thích hợp, của gia đình bệnh nhân\nđược đánh giá và ghi lại trong hồ sơ y tế của bệnh nhân. Điều này phải bao gồm, tối\nthiểu, những điều sau:\n•\nNgôn ngữ mà bệnh nhân muốn sử dụng để giáo dục\n•\nBiểu mẫu mà bệnh nhân muốn sử dụng để giáo dục\n•\nAi nên được giáo dục ngoài bệnh nhân (ví dụ: vợ/chồng hoặc người chăm sóc)\n•\nBất kỳ rào cản nào đã biết đối với việc học\n2.  Giáo dục được cung cấp cho bệnh nhân và gia đình được ghi lại trong hồ sơ y tế của\nbệnh nhân. (Xem thêm ACC.04.01, ME 5)\n3.  Bệnh viện có quy trình để xác minh rằng bệnh nhân và gia đình thừa nhận đã nhận và hiểu\nđược giáo dục được cung cấp. (Xem thêm ACC.04.01, ME 5)\n\nPatient-Centered\n\nPhần III: Tiêu chuẩn quản lý tổ chức chăm sóc sức khỏe\nPhần III:\nTiêu chuẩn quản lý tổ\nchức chăm sóc sức khỏe\n\nQuản lý cơ sở và an\ntoàn (FMS)\n\nTổng quan\nCác tổ chức chăm sóc sức khỏe nỗ lực cung cấp các cơ sở an toàn, chức năng và hỗ trợ cho bệnh nhân, gia\nđình, nhân viên và khách thăm. Để đạt được mục tiêu này, cơ sở vật chất, thiết bị y tế và các thiết bị khác,\ncũng như con người phải được quản lý hiệu quả. Đặc biệt, ban quản lý phải nỗ lực thực hiện những điều\nsau:\n•\nXác định, giảm thiểu và kiểm soát các mối nguy hiểm và rủi ro.\n•\nPhòng ngừa tai nạn và thương tích.\n•\nDuy trì các điều kiện an toàn.\n\nQuản lý hiệu quả bao gồm lập kế hoạch liên ngành, giáo dục và giám sát như sau:\n•\nCác nhà lãnh đạo lập kế hoạch về không gian, thiết bị và nguồn lực cần thiết để hỗ trợ an toàn và hiệu\nquả cho các dịch vụ lâm sàng được cung cấp.\n•\nTất cả nhân viên đều được đào tạo về cơ sở, cách giảm thiểu rủi ro và cách theo dõi và báo cáo các tình\nhuống gây rủi ro.\n•\nTiêu chí hiệu suất được sử dụng để đánh giá các hệ thống quan trọng và xác định các cải tiến cần thiết.\n•\nĐánh giá rủi ro toàn diện trên toàn cơ sở được phát triển và giám sát đối với từng chương trình quản lý\nvà an toàn cơ sở khi cần thiết.\n\nCác chương trình được viết ra và bao gồm tám lĩnh vực sau, khi phù hợp với cơ sở và hoạt động của tổ chức:\n1. An toàn—Mức độ mà các tòa nhà, khu vực xây dựng, mặt bằng và thiết bị của tổ chức không gây nguy\nhiểm hoặc rủi ro cho bệnh nhân, nhân viên hoặc khách\n2. An ninh—Tiến hành đánh giá rủi ro liên tục để tăng cường bảo vệ khỏi mất mát, phá hủy, giả mạo hoặc\ntruy cập hoặc sử dụng trái phép\n3. Vật liệu và chất thải nguy hại—Việc xử lý, lưu trữ và sử dụng vật liệu phóng xạ và các vật liệu khác được\nkiểm soát và chất thải nguy hại được xử lý an toàn.\n4. An toàn phòng cháy chữa cháy—Tiến hành đánh giá rủi ro liên tục để tăng cường bảo vệ tài sản và người\ncư trú khỏi hỏa hoạn và khói.\n5. Thiết bị y tế—Thiết bị được lựa chọn, bảo trì và sử dụng theo cách giảm thiểu rủi ro.\n6. Hệ thống tiện ích—Hệ thống điện, nước và các tiện ích khác được bảo trì để giảm thiểu rủi ro do sự cố\nvận hành.\n7. Quản lý tình trạng khẩn cấp—Xác định rủi ro và lập kế hoạch ứng phó với dịch bệnh, thảm họa và tình\ntrạng khẩn cấp, bao gồm đánh giá tính toàn vẹn về mặt cấu trúc và phi cấu trúc của môi trường chăm sóc\nbệnh nhân.\n8. Xây dựng và cải tạo—Xác định và đánh giá rủi ro đối với bệnh nhân, nhân viên và khách thăm trong quá\ntrình xây dựng, cải tạo, phá dỡ và các hoạt động bảo trì khác.\n\nKhi tổ chức có các thực thể không phải bệnh viện trong các cơ sở chăm sóc bệnh nhân cần được khảo sát\n(chẳng hạn như quán cà phê hoặc cửa hàng quà tặng do cá nhân sở hữu), tổ chức có nghĩa vụ đảm bảo rằng\ncác thực thể độc lập này tuân thủ các chương trình quản lý cơ sở và an toàn sau:\n•\nChương trình an toàn và bảo mật\n•\nChương trình quản lý vật liệu nguy hiểm và chất thải\n\n• Chương trình phòng cháy chữa cháy\n• Xây dựng và cải tạo\n\nLuật pháp, quy định và hoạt động thanh tra của chính quyền địa phương phần lớn quyết định cách thiết kế,\nsử dụng và bảo trì cơ sở. Tất cả các tổ chức, bất kể quy mô và nguồn lực, đều phải tuân thủ các yêu cầu này\nnhư một phần trách nhiệm của họ đối với bệnh nhân, gia đình, nhân viên và khách đến thăm.\n\nCác tổ chức được yêu cầu tuân thủ luật pháp và quy định, bao gồm cả quy định về xây dựng và phòng cháy\nchữa cháy. Họ có hiểu biết về các chi tiết của cơ sở vật chất mà họ chiếm giữ bằng cách thực hiện các cuộc\nthanh tra cơ sở thường xuyên. Họ chủ động thu thập dữ liệu và thực hiện các chiến lược để giảm thiểu rủi ro\nvà cải thiện môi trường chăm sóc bệnh nhân.\n\nTiêu chuẩn\nSau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà\nkhông có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng\nxem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và","m":[],"sec":"Giáo dục bệnh nhân và gia đình"},{"c":"PCI.01.00","ch":"PCI","t":"Một hoặc nhiều cá nhân có trình độ sẽ hướng dẫn việc thực hiện chương trình phòng ngừa và kiểm soát nhiễm trùng của bệnh viện và giám sát các hoạt động cần thiết để thực hiện chương trình trong toàn bệnh viện.","p":"Tiêu chuẩn này liên quan đến trình độ chuyên môn và giám sát chương trình phòng ngừa và kiểm soát nhiễm trùng.\nHiệu quả của chương trình phòng ngừa và kiểm soát nhiễm trùng tại bệnh viện trong việc xác định và giảm thiểu\nrủi ro mắc và lây truyền nhiễm trùng giữa bệnh nhân, nhân viên, bác sĩ, nhân viên hợp đồng, tình nguyện viên, sinh\nviên và khách thăm phụ thuộc vào sự lãnh đạo có năng lực và hiệu quả. Cấu trúc và phạm vi của chương trình\nphòng ngừa và kiểm soát nhiễm trùng tuân thủ mọi luật và quy định hiện hành, tiêu chuẩn quốc gia hoặc tiêu\nchuẩn của ngành chăm sóc sức khỏe và các hướng dẫn dựa trên bằng chứng, đồng thời dựa trên dân số bệnh nhân\ncủa bệnh viện, phạm vi và mức độ phức tạp của các dịch vụ, vị trí địa lý, khối lượng bệnh nhân, mức độ rủi ro và\nsố lượng nhân viên và bác sĩ. Cơ quan quản lý phê duyệt chương trình và các nhà lãnh đạo cung cấp các nguồn lực\nđể triển khai chương trình. Cần có sự hướng dẫn và giám sát có năng lực để thực hiện chương trình nhằm đưa\nphòng ngừa và kiểm soát nhiễm trùng trở thành một phần trong cách bệnh viện thực hiện sứ mệnh và các ưu tiên\nchiến lược của mình.\n\nMột hoặc nhiều cá nhân đủ tiêu chuẩn phải giám sát hoạt động của chương trình. Điều này đòi hỏi kiến thức và\nkinh nghiệm trong nhiều khía cạnh của vai trò, bao gồm nhưng không giới hạn ở kiến thức về những điều sau:\n•\nLây truyền bệnh, bao gồm các biện pháp cách ly đối với bệnh nhân bị nhiễm trùng hoặc bệnh nhân bị suy giảm miễn\ndịch\n\n•\nKiến thức về các quy trình có nguy cơ cao, chẳng hạn như các hoạt động của Phòng cung cấp vô\ntrùng trung tâm, pha chế thuốc vô trùng và thẩm phân máu\n•\nKhả năng triển khai các hướng dẫn dựa trên bằng chứng\n•\nKhả năng tiến hành thu thập và phân tích dữ liệu, viết báo cáo và trình bày dữ liệu\n•\nKhả năng giao tiếp hiệu quả\n\nCá nhân lãnh đạo chương trình phòng ngừa và kiểm soát nhiễm trùng có kinh nghiệm trong cả phòng\nngừa và kiểm soát nhiễm trùng và lãnh đạo. Các bằng cấp cần thiết cho vai trò này sẽ phụ thuộc vào các\nhoạt động của chương trình. Các bằng cấp của cá nhân có thể đạt được thông qua giáo dục, đào tạo, kinh\nnghiệm, chứng nhận hoặc giấy phép và/hoặc khả năng lãnh đạo đã được chứng minh.\nCá nhân giám sát chương trình phòng ngừa và kiểm soát nhiễm trùng cũng lựa chọn nhân viên phòng ngừa\nvà kiểm soát nhiễm trùng có các bằng cấp và năng lực cần thiết cho chương trình theo quy định của bệnh\nviện. Một số cá nhân chủ chốt của chương trình phòng ngừa và kiểm soát nhiễm trùng, chẳng hạn như\nbác sĩ vô địch hoặc y tá trưởng nhóm dự án phòng ngừa nhiễm trùng, có thể làm việc trong một khoa/dịch\nvụ trong bệnh viện và cần được chương trình phòng ngừa và kiểm soát nhiễm trùng hỗ trợ. Nhân viên\nchương trình phòng ngừa và kiểm soát nhiễm trùng cũng hiểu cách đưa các ưu tiên của toàn bệnh viện và\ncác ưu tiên của khoa/dịch vụ vào một chương trình tổng thể được phối hợp. Nhân viên chương trình phối\nhợp và tổ chức các hoạt động trong toàn bệnh viện và hỗ trợ các hoạt động liên quan đến các ưu tiên của\nbệnh viện.\nCá nhân đủ tiêu chuẩn giám sát chương trình phòng ngừa và kiểm soát nhiễm trùng có trách nhiệm thiết\nlập các ưu tiên và đảm bảo tiến độ thực hiện các ưu tiên đó. Cá nhân này xác định các lĩnh vực có nguy cơ\ncao để phòng ngừa và kiểm soát nhiễm trùng và giám sát hoặc chỉ định người được bổ nhiệm để giám sát\ncác lĩnh vực này. Nhân viên trong toàn bệnh viện hỗ trợ chương trình phòng ngừa và kiểm soát nhiễm\ntrùng. Chương trình được phối hợp với chương trình chất lượng và an toàn bệnh nhân của bệnh viện,\ncũng như chương trình quản lý và an toàn cơ sở. Cá nhân này chịu trách nhiệm phối hợp với các nhà lãnh\nđạo bệnh viện về các ưu tiên, nguồn lực và cải tiến liên tục liên quan đến chương trình phòng ngừa và\nkiểm soát nhiễm trùng.\nDữ liệu được báo cáo cho các cơ quan y tế công cộng địa phương, quốc gia, khu vực và/hoặc toàn cầu khi\ncần thiết.\nBệnh viện cũng thực hiện các hành động để phản hồi các báo cáo do các cơ quan y tế công cộng ban hành,\ntùy theo trường hợp áp dụng cho bệnh viện và nhóm bệnh nhân của bệnh viện.\n\nCác yếu tố đo lường được của PCI.01.00\n1.\nMột hoặc nhiều cá nhân đủ tiêu chuẩn giám sát chương trình phòng ngừa và kiểm soát nhiễm trùng\nvà đảm bảo rằng chương trình tuân thủ luật pháp và quy định của địa phương và quốc gia cũng như\ncác hướng dẫn kiểm soát nhiễm trùng hiện hành. (Xem thêm GLD.06.00, ME 1)\n2.\nTrình độ của cá nhân giám sát và trình độ của nhân viên cho chương trình phòng ngừa và kiểm soát\nnhiễm trùng được xác định bởi các nhà lãnh đạo bệnh viện, dựa trên số lượng bệnh nhân của bệnh\nviện, phạm vi và mức độ phức tạp của các dịch vụ, vị trí địa lý, khối lượng bệnh nhân, mức độ rủi ro\nvà số lượng nhân viên và bác sĩ hành nghề chăm sóc sức khỏe.\n3.\nCá nhân này phối hợp với các nhà lãnh đạo bệnh viện về các ưu tiên, nguồn lực và cơ hội cải thiện\nchất lượng liên quan đến chương trình phòng ngừa và kiểm soát nhiễm trùng.\n4.\nBệnh viện báo cáo kết quả chương trình phòng ngừa và kiểm soát nhiễm trùng cho các cơ quan y tế\ncông cộng khi được yêu cầu.\n5.\nBệnh viện thực hiện hành động thích hợp đối với các báo cáo từ các cơ quan y tế công cộng có liên\nquan.","m":[],"sec":"Trách nhiệm"},{"c":"PCI.01.01","ch":"PCI","t":"Bệnh viện điều phối các hoạt động phòng ngừa và kiểm soát nhiễm trùng trên tất cả các khoa và dịch vụ. 248 Prevention and Control of Infections (PCI) PreventIon and Control of InfeCtIonS (PCI).","p":"Tiêu chuẩn này liên quan đến việc tích hợp chương trình phòng ngừa và kiểm soát nhiễm trùng với tất cả các khoa và\ndịch vụ của bệnh viện, cũng như với chương trình chất lượng và an toàn cho bệnh nhân. Các hoạt động phòng ngừa và\nkiểm soát nhiễm trùng phải được phối hợp trong toàn bệnh viện và bao gồm tất cả các dịch vụ và khoa để giải quyết hiệu\nquả các rủi ro nhiễm trùng hiện diện trong toàn bệnh viện. Các hoạt động phòng ngừa và kiểm soát nhiễm trùng tác động\nđến tất cả các khu vực và chức năng của bệnh viện và liên quan đến các cá nhân ở tất cả các khoa và dịch vụ. Phải có một\ncơ chế chính thức để phối hợp các hoạt động của chương trình trong toàn bệnh viện, bao gồm việc giao tiếp với tất cả\ncác bộ phận của bệnh viện. Chức năng và hành động của cơ chế phối hợp này phải được ghi lại. Bệnh viện sử dụng thông\ntin này để xem xét hiệu quả của các hoạt động phối hợp và theo dõi việc cải thiện liên tục công tác phòng ngừa và kiểm\nsoát nhiễm trùng.\n\nCác nhà lãnh đạo bệnh viện phải tham gia vào cơ chế phối hợp và chịu trách nhiệm về hiệu quả của chương trình. Các\nbác sĩ, y tá và các nhân viên khác được đại diện và tham gia vào các hoạt động với các chuyên gia phòng ngừa và kiểm soát\nnhiễm trùng. Các nhân viên khác nên được đưa vào tùy theo quy mô và mức độ phức tạp của các dịch vụ của bệnh viện\nvà có thể bao gồm những người sau:\n• Nhà dịch tễ học\n• Bác sĩ chuyên khoa bệnh truyền nhiễm hoặc một chuyên gia về bệnh lâm sàng khác\n• Chuyên gia thống kê\n• Quản lý khử trùng trung tâm\n• Nhà vi sinh học\n• Dịch vụ dọn phòng\n• Dịch vụ cơ sở vật chất\n• Chuyên gia công nghệ thông tin\n• Dược sĩ\n• Bệnh nhân và gia đình\n\nBệnh viện xác định cơ chế phối hợp hiệu quả nhất cho nhu cầu của mình. Ví dụ về cơ chế phối hợp bao gồm nhưng\nkhông giới hạn ở các nhóm làm việc, ủy ban phối hợp hoặc lực lượng đặc nhiệm.\n\nTrách nhiệm của cơ chế phối hợp được chỉ định này bao gồm những điều sau:\n• Thiết lập các chính sách và thủ tục cho chương trình\n• Đặt ra các tiêu chí để xác định các bệnh nhiễm trùng liên quan đến chăm sóc sức khỏe\n• Thiết lập các phương pháp thu thập dữ liệu (giám sát)\n• Thiết kế các chiến lược để giải quyết các rủi ro phòng ngừa và kiểm soát nhiễm trùng\n• Quy trình báo cáo\n• Giao tiếp với tất cả các bộ phận của bệnh viện\n• Phối hợp ứng phó với các đợt bùng phát nhiễm trùng\n\nCác yếu tố đo lường được của PCI.01.01\n1.\nCó một cơ chế phối hợp liên ngành chính thức như một ủy ban cho chương trình phòng ngừa và\nkiểm soát nhiễm trùng có sự tham gia của các chuyên gia phòng ngừa và kiểm soát nhiễm trùng.\n2.\nTất cả các khoa và dịch vụ của bệnh viện đều được đưa vào chương trình phòng ngừa và kiểm soát\nnhiễm trùng. (Xem thêm FMS.03.00, ME 1)\n3.\nChức năng và hoạt động của cơ chế phối hợp được ghi chép lại.\n4.\nBệnh viện xác định khoảng thời gian cho các cuộc họp và nội dung của ủy ban, dựa trên luật pháp\nvà quy định, và các yêu cầu của hướng dẫn kiểm soát nhiễm trùng và chính sách của bệnh viện.\n5.\nChương trình phòng ngừa và kiểm soát nhiễm trùng hỗ trợ nhân viên trên toàn bệnh viện cho các\nhoạt động phòng ngừa và kiểm soát nhiễm trùng.","m":[]},{"c":"PCI.01.02","ch":"PCI","t":"Lãnh đạo bệnh viện cung cấp nguồn lực để hỗ trợ chương trình phòng ngừa và kiểm soát nhiễm trùng.","p":"Tiêu chuẩn này liên quan đến việc cung cấp đủ nguồn lực, bao gồm số lượng nhân viên cần thiết cho chương trình\nphòng ngừa và kiểm soát nhiễm trùng. Chương trình phòng ngừa và kiểm soát nhiễm trùng phải được cung cấp đủ\nnhân viên và nguồn lực, bao gồm hỗ trợ hành chính, để đạt được các mục tiêu và trách nhiệm của chương trình, đáp\nứng nhu cầu của bệnh viện và đáp ứng hoặc vượt quá luật pháp và quy định của địa phương. Số lượng nhân viên\nđược xác định bởi quy mô bệnh viện, mức độ phức tạp của các dịch vụ và mức độ rủi ro; phạm vi của chương trình;\nvà luật pháp và quy định, tiêu chuẩn của ngành chăm sóc sức khỏe quốc gia và tiêu chuẩn của hiệp hội chuyên môn.\n\nLãnh đạo bệnh viện đảm bảo rằng có đủ nguồn lực để hỗ trợ chương trình phòng ngừa và kiểm soát nhiễm trùng.\nĐiều này bao gồm:\n• Chỉ định một hoặc nhiều cá nhân đủ tiêu chuẩn để giám sát chương trình và các khu vực có nguy cơ cao\n• Nhân viên cung cấp giáo dục về chương trình phòng ngừa và kiểm soát nhiễm trùng\n• Số lượng nhân viên lâm sàng cho phép thực hành an toàn, bao gồm các hoạt động phòng ngừa và kiểm soát nhiễm\ntrùng\n\nChương trình phòng ngừa và kiểm soát nhiễm trùng yêu cầu các nguồn lực để cung cấp giáo dục cho tất cả nhân viên\nvà mua vật tư. Lãnh đạo bệnh viện đảm bảo rằng chương trình có đủ nguồn lực để thực hiện hiệu quả các mục tiêu và\ntrách nhiệm của mình. Lãnh đạo bệnh viện phê duyệt và phân bổ nguồn lực và đảm bảo rằng chúng được cung cấp\ncho chương trình phòng ngừa và kiểm soát nhiễm trùng theo đúng mục đích và đáp ứng nhu cầu của bệnh viện.\n\nCần có hệ thống quản lý thông tin để hỗ trợ thu thập, tổng hợp và phân tích dữ liệu, theo dõi và xu hướng rủi ro, tỷ\nlệ và xu hướng trong các bệnh nhiễm trùng liên quan đến chăm sóc sức khỏe. Các chức năng quản lý thông tin hỗ trợ\nphân tích và diễn giải dữ liệu và trình bày các phát hiện. Dữ liệu và thông tin của chương trình phòng ngừa và kiểm\nsoát nhiễm trùng được quản lý bằng chương trình cải tiến liên tục của bệnh viện.\n\nCác yếu tố đo lường được của PCI.01.02\n1.\nLãnh đạo bệnh viện phê duyệt mức độ biên chế và cung cấp biên chế cho chương trình phòng ngừa\nvà kiểm soát nhiễm trùng theo quy mô bệnh viện, mức độ phức tạp của các hoạt động, mức độ rủi\nro và phạm vi của chương trình.\n2.\nLãnh đạo bệnh viện đảm bảo rằng chương trình phòng ngừa và kiểm soát nhiễm trùng nhận được\ncác nguồn lực cần thiết để đáp ứng các mục tiêu và trách nhiệm của chương trình.\n3.\nHệ thống quản lý thông tin hỗ trợ chương trình phòng ngừa và kiểm soát nhiễm trùng.\n\nMục tiêu của Chương trình Phòng ngừa và Kiểm soát Nhiễm trùng","m":[],"sec":"Trách nhiệm"},{"c":"PCI.02.00","ch":"PCI","t":"Bệnh viện sử dụng phương pháp dựa trên dữ liệu rủi ro để thiết lập các ưu tiên, thực hiện các biện pháp can thiệp và theo dõi hiệu quả của chương trình phòng ngừa và kiểm soát nhiễm trùng liên quan đến chăm sóc sức khỏe.","p":"Nhiễm trùng liên quan đến chăm sóc sức khỏe, bao gồm cả những nhiễm trùng do vi khuẩn đa kháng thuốc\n(MDRO) gây ra, có thể phòng ngừa được, gây ra tỷ lệ mắc bệnh và tử vong đáng kể, đồng thời làm tăng đáng\nkể chi phí chăm sóc cho bệnh nhân và bệnh viện. Đánh giá rủi ro chính thức bằng cách sử dụng phương pháp\ntiếp cận dựa trên dữ liệu giúp bệnh viện xác định các khu vực và quy trình có nguy cơ cao, xây dựng các biện\npháp can thiệp hiệu quả và theo dõi hiệu quả của các biện pháp can thiệp đó để thực hiện các thay đổi khi cần\nthiết. Quy trình phòng ngừa và kiểm soát nhiễm trùng được thiết kế để giảm nguy cơ nhiễm trùng cho bệnh\nnhân, nhân viên và những người khác. Nhiễm trùng liên quan đến chăm sóc sức khỏe và vi khuẩn đa kháng\nthuốc gây ra rủi ro đáng kể cho bệnh nhân và cộng đồng. Nhiễm trùng liên quan đến chăm sóc sức khỏe\nthường được coi là có thể phòng ngừa được và phản ánh chất lượng chăm sóc của bệnh viện. Vi khuẩn đa\nkháng thuốc là mối đe dọa nghiêm trọng vì có rất ít loại thuốc có hiệu quả chống lại các tác nhân gây bệnh đang\ntiến hóa nhanh chóng này.\n\nMỗi bệnh viện phải xác định các rủi ro nhiễm trùng đối với bệnh nhân, nhân viên và khách đến thăm. Các ví dụ\nvề các rủi ro nhiễm trùng này bao gồm:\n• Các bệnh nhiễm trùng và sinh vật gây nhiễm trùng có ý nghĩa về mặt dịch tễ học (xem","m":[],"sec":"Mục tiêu của Chương trình Phòng ngừa và Kiểm soát Nhiễm trùng"},{"c":"PCI.02.01","ch":"PCI","t":"Phòng thí nghiệm thực hiện một quy trình nhằm giảm thiểu nguy cơ nhiễm trùng do tiếp xúc với các bệnh truyền nhiễm và vật liệu và chất thải nguy hại sinh học.","p":"Nhân viên làm việc trong phòng thí nghiệm có nguy cơ tiếp xúc với vật liệu và chất thải truyền nhiễm và nguy hại sinh\nhọc. Phòng thí nghiệm phải triển khai các quy trình để xác định và giảm nguy cơ nhiễm trùng cho nhân viên. Bệnh viện\ntriển khai các chính sách, quy trình và thực hành để giảm nguy cơ tiếp xúc với vật liệu nguy hại sinh học. Các trường\nhợp tiếp xúc và nhiễm trùng mắc phải trong phòng thí nghiệm được báo cáo ngay lập tức cho bộ phận phòng ngừa và\nkiểm soát nhiễm trùng, cho các nhà lãnh đạo bệnh viện và cho các cơ quan y tế công cộng khi cần thiết. Bệnh viện xác\nđịnh các mối nguy hại về an toàn sinh học trong phòng thí nghiệm và triển khai các chính sách và quy trình để giải quyết\ncác mối nguy hại đó. Nhân viên được đào tạo về các chính sách và quy trình và luôn tuân thủ các yêu cầu này.\n\nVí dụ về các tai nạn hoặc thương tích có thể khiến nhân viên tiếp xúc với các mối nguy sinh học bao gồm\nnhưng không giới hạn ở những trường hợp sau:\n• Tiếp xúc với các tác nhân gây nhiễm trùng\n• Chấn thương do vật sắc nhọn và kim tiêm\n• Vô tình nuốt phải\n• Tiếp xúc với các tác nhân có khả năng gây nhiễm trùng với niêm mạc\n\nKhi phát hiện ra các vấn đề trong quá trình thực hành hoặc xảy ra tai nạn, bệnh viện sẽ thực hiện các hành\nđộng khắc phục, được ghi chép và xem xét lại. Việc xem xét hoặc đánh giá các hành động khắc phục đảm bảo\nrằng các hành động đó có hiệu quả và sẽ ngăn ngừa các sự cố hoặc tai nạn xảy ra trong tương lai.\nTối thiểu, các yêu cầu được thực hiện phải giải quyết các mối nguy và thực hành an toàn sinh học sau:\n• Kiểm soát việc tiếp xúc với khí dung và giọt bắn (ví dụ: khi trộn, siêu âm, ly tâm\nvà đốt các vòng tiêm chủng).\n• Mặc áo khoác, áo choàng hoặc đồng phục phòng thí nghiệm để bảo vệ quần áo thường ngày và ngăn\nngừa ô nhiễm.\n• Tủ an toàn sinh học được sử dụng khi luật pháp và quy định, hướng dẫn của nhà sản xuất hoặc\ntiêu chuẩn thực hành chuyên môn yêu cầu.\n• Các quy định chi phối các thủ tục về cách xử lý tai nạn và thương tích trong phòng thí nghiệm, chẳng\nhạn như tiếp xúc với các tác nhân truyền nhiễm, vết cắt vô tình, thương tích do kim tiêm, vô tình nuốt\nphải và tiếp xúc với các tác nhân có khả năng truyền nhiễm với niêm mạc. Các quy tắc này bao gồm\nnhững điều sau:\no Quy trình khử nhiễm\no Liên hệ với ai để được điều trị khẩn cấp\no Vị trí và cách sử dụng thiết bị an toàn\n• Có các quy trình bằng văn bản xác định việc thu thập, vận chuyển và xử lý an toàn tất cả các mẫu vật,\nbao gồm lệnh cấm những điều sau đối với bất kỳ ai trong khu vực kỹ thuật của phòng xét nghiệm:\no Ăn hoặc uống\no Hút thuốc\no Sử dụng mỹ phẩm\no Thao tác với kính áp tròng\no Hút bằng pipet miệng\n• Sử dụng tủ an toàn sinh học an toàn khi thao tác với các vật liệu truyền nhiễm có thể tạo ra khí dung\nvà sử dụng phân loại tủ an toàn sinh học phù hợp cho các vi sinh vật đang được xử lý\n• Đào tạo cho nhân viên phòng xét nghiệm về các biện pháp phòng ngừa, phương thức lây truyền và\nphòng ngừa các tác nhân gây bệnh lây truyền qua đường máu\n• Các quy trình để quản lý và giảm nguy cơ tiếp xúc với các bệnh truyền nhiễm (ví dụ: COVID-19,\nEbola, MERS, bệnh lao, Zika, các tác nhân gây bệnh truyền nhiễm tiềm ẩn khác chưa biết)\nCác yếu tố đo lường được của PCI.02.01\n1. Phòng xét nghiệm thực hiện các chính sách và quy trình bằng văn bản để giảm thiểu rủi ro nhiễm trùng.\n2. Bệnh viện báo cáo các ca nhiễm trùng mắc phải trong phòng xét nghiệm theo định nghĩa trong chính sách và\ntuân thủ luật pháp và quy định.\n3. Phòng xét nghiệm tuân thủ các quy tắc an toàn sinh học đối với các hoạt động liên quan:\n•\nKiểm soát việc tiếp xúc với khí dung và giọt bắn.\n•\nMặc áo khoác, áo choàng hoặc đồng phục phòng xét nghiệm.\n•\nSử dụng tủ an toàn sinh học khi luật pháp và quy định hoặc hướng dẫn của nhà sản xuất yêu cầu.\n•\nCác quy trình giải thích cách xử lý tai nạn và thương tích, bao gồm các quy trình khử nhiễm, quy trình\nđiều trị khẩn cấp, vị trí và cách sử dụng thiết bị an toàn.\n•\nCác quy trình xác định cách thu thập, vận chuyển và xử lý an toàn tất cả các mẫu vật.\n•\nĐào tạo cho nhân viên phòng xét nghiệm bao gồm các biện pháp phòng ngừa, phương thức lây truyền và\nphòng ngừa phơi nhiễm với các tác nhân gây bệnh qua đường máu.\n•\nCác quy trình giải quyết cách quản lý và giảm thiểu rủi ro phơi nhiễm với các bệnh truyền nhiễm.\n\n4. Bệnh viện thực hiện các hành động khắc phục, được ghi chép và xem xét khi phát hiện ra các vấn đề trong quá\ntrình thực hành hoặc xảy ra tai nạn.\n\nThiết bị, dụng cụ và vật tư y tế","m":[]},{"c":"PCI.03.00","ch":"PCI","t":"Bệnh viện giảm nguy cơ nhiễm trùng liên quan đến thiết bị, dụng cụ và vật tư y tế/phẫu thuật bằng cách vệ sinh, khử trùng, tiệt trùng và bảo quản đúng cách.","p":"Không vệ sinh, khử trùng, tiệt trùng và bảo quản thiết bị, dụng cụ và vật tư đúng cách sẽ gây ra rủi ro cao cho bệnh\nnhân, nhân viên và những người khác trong bệnh viện do tiếp xúc với các tác nhân gây bệnh tiềm ẩn, bao gồm\nMDRO, tác nhân gây bệnh qua đường máu, nội độc tố, hóa chất như chất bảo quản và các vật liệu hữu cơ hoặc vô\ncơ khác. Trung tâm Kiểm soát và Phòng ngừa Dịch bệnh Hoa Kỳ (CDC) định nghĩa vệ sinh là: \"loại bỏ vật liệu lạ (ví\ndụ: đất và vật liệu hữu cơ) khỏi các vật thể\". CDC tiếp tục nói rằng \"[vệ sinh] thường được thực hiện bằng nước có\nchất tẩy rửa hoặc các sản phẩm có chứa enzym. Cần vệ sinh kỹ lưỡng trước khi khử trùng và tiệt trùng ở mức độ cao\nvì các vật liệu vô cơ và hữu cơ còn sót lại trên bề mặt dụng cụ sẽ ảnh hưởng đến hiệu quả của các quy trình này\".\n\nNăm 2008, Ủy ban Cố vấn về Thực hành Kiểm soát Nhiễm trùng Chăm sóc Sức khỏe của CDC đã công nhận\nphương pháp khử trùng và tiệt trùng tại các Cơ sở Chăm sóc Sức khỏe của Earle H. Spaulding bằng phương pháp ba\ncấp độ. Phân loại bề mặt Spaulding bao gồm các nội dung sau:\n• Mức 1—Quan trọng: Các vật thể xâm nhập vào mô hoặc hệ thống mạch máu thông thường vô trùng và cần được\nkhử trùng\n• Mức 2—Bán quan trọng: Các vật thể tiếp xúc với niêm mạc hoặc da không nguyên vẹn và cần được khử trùng ở\nmức độ cao, tiêu diệt hầu hết các bào tử vi khuẩn ngoại trừ một số ít\n• Mức 3—Không quan trọng: Các vật thể tiếp xúc với da nguyên vẹn nhưng không tiếp xúc với niêm mạc và cần\nđược khử trùng ở mức độ thấp\n\nCần tuân thủ rõ ràng hướng dẫn sử dụng của nhà sản xuất đối với các dụng cụ và thiết bị, cũng như thiết bị hoặc tác\nnhân được sử dụng để làm sạch, khử trùng hoặc tiệt trùng chúng, cùng với các luật và quy định hiện hành. Cũng cần\ntham khảo các hướng dẫn dựa trên bằng chứng và các tiêu chuẩn thực hành chuyên môn để xác định\nmức độ khử trùng hoặc tiệt trùng cần thiết cho các vật phẩm. Tuy nhiên, các luật và quy định và hướng dẫn sử dụng\ncủa nhà sản xuất được ưu tiên hơn các hướng dẫn dựa trên bằng chứng hoặc các tiêu chuẩn thực hành chuyên môn\nkhi chúng xung đột. Khi hướng dẫn của nhà sản xuất thiết bị y tế xung đột với hướng dẫn của nhà sản xuất về thiết\nbị khử trùng hoặc tiệt trùng cấp độ cao tự động, bệnh viện phải có quy trình để giải quyết\nxung đột này. Điều này có thể bao gồm liên hệ trực tiếp với nhà sản xuất để được hướng dẫn. Trong những trường\nhợp không có hướng dẫn nào trong số này đưa ra, thì quyết định về cách tiến hành phải dựa trên sự đồng thuận của\nchuyên gia bằng cách sử dụng quy trình dựa trên bằng chứng. Trong mọi trường hợp, phải tuân thủ tiêu chuẩn\nnghiêm ngặt hơn nếu luật pháp và quy định hoặc hướng dẫn sử dụng của nhà sản xuất xung đột.\n\nViệc vệ sinh, khử trùng và tiệt trùng thiết bị, dụng cụ và vật tư y tế liên quan đến khử trùng cấp độ thấp, trung bình\nhoặc cao (HLD) hoặc các tác nhân và quy trình tiệt trùng, dựa trên hướng dẫn sử dụng (IFU) của nhà sản xuất;\nhướng dẫn từ các tổ chức đã thành lập như Hiệp hội vì sự tiến bộ của thiết bị y tế (AAMI) và Tổ chức tiêu chuẩn\nquốc tế (ISO) và các tổ chức khác; mục đích sử dụng dự kiến của mặt hàng; và các tiêu chuẩn như Phân loại\nSpaulding. Một số thiết bị hoặc dụng cụ có thể thuộc nhiều hơn một phân loại tùy thuộc vào cách sử dụng chúng.\n\nViệc lưu trữ các mặt hàng này cũng được xác định theo Phân loại Spaulding, cùng với IFU của nhà sản xuất, luật\nvà quy định, tiêu chuẩn ngành chăm sóc sức khỏe quốc gia, tiêu chuẩn thực hành chuyên môn và hướng dẫn dựa\ntrên bằng chứng. Như đã nêu trước đó, bệnh viện phải phân biệt cách tiến hành khi hướng dẫn từ các nguồn này\nxung đột. Trong mọi trường hợp, thiết bị phải được lưu trữ theo cách ngăn ngừa ô nhiễm hoặc mất tính vô\ntrùng trước khi sử dụng. Điều quan trọng là các quy trình có rủi ro cao này phải được tích hợp vào chương trình\nphòng ngừa và kiểm soát nhiễm trùng, cũng như chương trình chất lượng và an toàn cho bệnh nhân, với sự giám\nsát của các nhà lãnh đạo bệnh viện.\n\nCác yếu tố đo lường được của PCI.03.00\n1.\nBệnh viện thực hiện các biện pháp phòng ngừa và kiểm soát nhiễm trùng thích hợp khi vệ sinh và khử trùng ở\nmức độ thấp và trung bình đối với thiết bị, dụng cụ và vật tư y tế không quan trọng, nhằm giải quyết các vấn đề\nsau:\n•\nSử dụng chất khử trùng đã được phê duyệt theo hướng dẫn trên nhãn sản phẩm, bao gồm chỉ định, pha\nloãng theo mục đích sử dụng cụ thể khi áp dụng, thời gian tiếp xúc và phương pháp sử dụng\n•\nSử dụng tác nhân khử trùng và phương pháp được nhà sản xuất thiết bị hoặc dụng cụ phê duyệt\n2.\nBệnh viện thực hiện các biện pháp phòng ngừa và kiểm soát nhiễm trùng thích hợp khi thực hiện khử\ntrùng và tiệt trùng ở mức độ cao đối với thiết bị, dụng cụ và vật tư y tế quan trọng, nhằm giải quyết các\nvấn đề sau:\n•\nSử dụng chất khử trùng hóa học đã được phê duyệt và chất khử trùng ở mức độ cao theo hướng dẫn trên\nnhãn sản phẩm và hướng dẫn của nhà sản xuất thiết bị\n•\nTài liệu bắt buộc cho các chu kỳ xử lý lại thiết bị, bao gồm nhưng không giới hạn ở nhật ký chu kỳ tiệt\ntrùng, tần suất thử nghiệm hóa học hoặc sinh học và kết quả thử nghiệm nồng độ thích hợp cho các hóa\nchất được sử dụng trong quá trình khử trùng ở mức độ cao\n•\nGiải quyết xung đột hoặc sự khác biệt giữa hướng dẫn của nhà sản xuất thiết bị y tế và hướng dẫn của nhà\nsản xuất đối với thiết bị khử trùng hoặc tiệt trùng ở mức độ cao tự động\n•\nTiêu chí và quy trình sử dụng tiệt trùng bằng hơi nước dùng ngay\n•\nCác hành động cần thực hiện trong trường hợp phát hiện lỗi hoặc hỏng hóc khi xử lý lại trước khi phát\nhành các mặt hàng đã xử lý lại hoặc sau khi các mặt hàng đã xử lý lại được sử dụng hoặc lưu trữ để sử dụng\nsau\n3.\nNhân viên xử lý lại thiết bị, dụng cụ và vật tư y tế/phẫu thuật được đào tạo ban đầu và liên tục và chứng minh\nnăng lực trong các quy trình vệ sinh và khử trùng; đào tạo và năng lực của nhân viên được ghi lại.\n4.\nMột hoặc nhiều cá nhân đủ tiêu chuẩn giám sát các quy trình vệ sinh, khử trùng, khử trùng và lưu trữ thiết\nbị, dụng cụ và vật tư.\n5.\nCác phương pháp vệ sinh, khử trùng, khử trùng và lưu trữ thiết bị và dụng cụ được phối hợp và áp dụng\nthống nhất trong toàn bệnh viện.\n6.\nThiết bị, dụng cụ và vật tư đã được vệ sinh, khử trùng và khử trùng được lưu trữ đúng cách tại các khu vực\nlưu trữ được chỉ định để ngăn ngừa ô nhiễm trước khi sử dụng.\n7.\nBệnh viện triển khai quy trình theo dõi các dụng cụ đã khử trùng và khử trùng ở mức độ cao được sử dụng\ncho các quy trình của bệnh nhân theo các chu kỳ khử trùng và khử trùng cụ thể, thiết bị và từng bệnh nhân.\n8.\nBệnh viện có quy trình bằng văn bản để xác định và thu hồi các dụng cụ cho từng chu kỳ khử trùng và thiết bị.","m":[],"sec":"Thiết bị, dụng cụ và vật tư y tế"},{"c":"PCI.03.01","ch":"PCI","t":"Bệnh viện thực hiện quy trình quản lý việc tái sử dụng các thiết bị dùng một lần theo yêu cầu của nhà sản xuất và bất kỳ luật và quy định hiện hành nào.","p":"Việc tái sử dụng các thiết bị và vật tư dùng một lần đã qua xử lý có nguy cơ không đạt hiệu suất hoặc không\nan toàn.\nMột số thiết bị dùng một lần chỉ có thể được tái sử dụng trong những trường hợp cụ thể khi được luật pháp\nvà quy định của địa phương và quốc gia cho phép. Tiêu chuẩn này đề cập đến các loại thiết bị y tế quan trọng\nvà bán quan trọng dùng một lần được liệt kê trong Phân loại Spaulding; tiêu chuẩn này không có nghĩa là bao\ngồm các thiết bị không quan trọng.\n\nCác thiết bị y tế được sản xuất để dùng một lần có thể được đánh dấu bằng ký hiệu như, hoặc các từ như\n\"chỉ dùng một lần\", \"không được tái sử dụng\" hoặc \"dùng một lần.”\n\nCó những rủi ro liên quan đến việc tái sử dụng các thiết bị dùng một lần đã qua xử lý, bao gồm nguy cơ nhiễm trùng\ntăng lên và nguy cơ hiệu suất không đạt yêu cầu hoặc không thể chấp nhận được sau khi tái sử dụng.\n\nKhi được phép tái sử dụng và tái sử dụng các thiết bị dùng một lần, quá trình tái sử dụng phải đáp ứng các tiêu chí\ngiống như nhà sản xuất ban đầu để đảm bảo thiết bị an toàn khi tái sử dụng, cả về chức năng và độ sạch.\n\nNhiều thiết bị có thiết kế phức tạp và do đó khó vệ sinh, khử trùng hoặc tiệt trùng. Quá trình tái sử dụng có thể\nảnh hưởng đến hiệu quả hoặc chức năng của thiết bị, dẫn đến nguy cơ thiết bị bị hỏng hoặc hỏng trong quá trình\nsử dụng. Các hóa chất được sử dụng để tái sử dụng có thể ăn mòn thiết bị và quá trình tái sử dụng có thể làm hỏng\nthiết bị. Hầu hết các thiết bị dùng một lần không được thiết kế để tái sử dụng, dẫn đến nguy cơ lây nhiễm chéo\ntăng lên. Nếu bệnh viện cho phép tái sử dụng các thiết bị dùng một lần đã qua xử lý, bệnh viện sẽ có chính sách\nhướng dẫn quá trình tái sử dụng và tái sử dụng. Chính sách này phù hợp với luật pháp và quy định quốc gia cũng\nnhư các tiêu chuẩn chuyên môn.\n\nCó sự giám sát đối với quy trình tái sử dụng các thiết bị dùng một lần đã qua xử lý dựa trên dữ liệu, nhu cầu của\nbệnh viện và các phương án thay thế cho việc tái sử dụng thiết bị. Danh sách các thiết bị dùng một lần được chấp\nthuận để tái sử dụng thường xuyên được xem xét để đảm bảo rằng danh sách này chính xác và cập nhật.\n\nNếu bệnh viện cho phép tái sử dụng và tái chế các thiết bị dùng một lần, chính sách của bệnh viện bao gồm những\nđiều sau:\n•\nPhù hợp với luật pháp, quy định và tiêu chuẩn của địa phương từ một cơ quan được công nhận\n•\nDanh sách các thiết bị và vật liệu dùng một lần có thể được tái sử dụng\n•\nQuy trình xác định thời điểm thiết bị dùng một lần không còn an toàn hoặc phù hợp để tái sử dụng\n•\nQuy trình vệ sinh cho từng thiết bị bắt đầu ngay sau khi sử dụng và tuân theo một giao thức rõ ràng\n•\nQuy trình xác định bệnh nhân đã sử dụng thiết bị y tế dùng một lần\n•\nĐánh giá chủ động về tính an toàn của việc tái sử dụng các vật dụng dùng một lần, bao gồm nhưng không giới\nhạn ở các biến cố bất lợi liên quan đến phẫu thuật như nhiễm trùng tại vị trí phẫu thuật hoặc bùng phát dịch\nbệnh hoặc nhiễm trùng\n•\nThu thập và phân tích dữ liệu về các biến cố bất lợi liên quan đến thiết bị dùng một lần để xác định rủi ro và\nthực hiện các hành động nhằm giảm thiểu những rủi ro này\n\nCác yếu tố đo lường được của PCI.03.01\n1.\nBệnh viện xác định, bằng văn bản, các thiết bị và vật liệu dùng một lần có thể được tái sử dụng theo luật pháp\nvà quy định của địa phương và quốc gia. (Xem thêm GHI.04.00, ME 4)\n2.\nBệnh viện có quy trình xác định thời điểm thiết bị dùng một lần không còn an toàn hoặc phù hợp để tái sử\ndụng.\n3.\nBệnh viện có quy trình vệ sinh, khử trùng hoặc tiệt trùng cho từng thiết bị dùng một lần, có thể tái sử dụng,\ntheo luật pháp và quy định, yêu cầu của nhà sản xuất hoặc các yêu cầu áp dụng khác.\n4.\nBệnh viện có quy trình bằng văn bản để theo dõi việc tái sử dụng các thiết bị dùng một lần cho từng bệnh\nnhân.\n5.\nBệnh viện thu thập và phân tích dữ liệu để tìm bất kỳ sự kiện bất lợi nào và thực hiện các cải tiến liên quan\nđến quy trình tái sử dụng.","m":[]},{"c":"PCI.03.02","ch":"PCI","t":"Bệnh viện triển khai quy trình quản lý thiết bị, vật tư hết hạn sử dụng và hư hỏng.","p":"Việc sử dụng vật tư hết hạn hoặc bị hư hỏng gây ra rủi ro cho bệnh nhân liên quan đến nhiễm trùng hoặc mất tính toàn vẹn\nvà chức năng. Bệnh viện phải triển khai quy trình quản lý hàng tồn kho thiết bị và vật tư, bao gồm ngày hết hạn và loại bỏ\nnhững mặt hàng đó khỏi dịch vụ khi đã lỗi thời. Điều này bao gồm quy trình xác định vật tư bị hư hỏng, chẳng hạn như\nmất tính toàn vẹn của bao bì hoặc hư hỏng làm ảnh hưởng đến mục đích sử dụng vật tư,\nvà loại bỏ những vật tư đó khỏi dịch vụ. Hầu hết các vật tư y tế đều được in ngày hết hạn. Nhà sản xuất không đảm bảo\ntính vô trùng, an toàn hoặc ổn định của mặt hàng sau ngày hết hạn. Một chính sách xác định quy trình đảm bảo quản lý đúng\ncách các vật tư đã hết hạn. Vật tư bị hư hỏng gây ra rủi ro cho bệnh nhân, vì\n\nvật tư có thể không còn hoạt động bình thường và độ sạch sẽ hoặc vô trùng của vật tư không thể được đảm\nbảo nếu bao bì bị hư hỏng.\n\nBệnh viện đảm bảo các điều kiện lưu trữ bảo vệ vật tư khỏi bị nhiễm bẩn và hư hỏng, ít nhất là giải quyết các vấn\nđề sau:\n• Các điều kiện do nhà sản xuất vật tư xác định\n• Độ ổn định của nhiệt độ và độ ẩm\n• Tiếp xúc với bụi, đất, nước và độ ẩm quá mức\n• Tiếp xúc với các phương tiện gây ô nhiễm khác như được lưu trữ theo cách tạo ra nguy cơ chúng có thể bị chạm\nvào bằng tay hoặc găng tay bị ô nhiễm hoặc tiếp xúc với các vi sinh vật có khả năng gây nhiễm\n\nCác yếu tố đo lường được của PCI.03.02\n1.\nBệnh viện thực hiện quy trình quản lý vật tư hết hạn.\n2.\nBệnh viện thực hiện quy trình quản lý vật tư bị hư hỏng.\n3.\nBệnh viện lưu trữ vật tư theo cách ngăn ngừa ô nhiễm hoặc hư hỏng, và trong điều kiện môi trường do nhà\nsản xuất khuyến nghị khi áp dụng\n\nVệ sinh môi trường","m":[],"sec":"Thiết bị, dụng cụ và vật tư y tế"},{"c":"PCI.04.00","ch":"PCI","t":"Chương trình phòng ngừa và kiểm soát nhiễm trùng cung cấp sự giám sát cho việc vệ sinh và khử trùng môi trường.","p":"Các biện pháp vệ sinh và khử trùng môi trường hiệu quả góp phần ngăn ngừa các bệnh nhiễm trùng\nmắc phải trong bệnh viện. Bệnh viện sử dụng các hướng dẫn dựa trên bằng chứng để chỉ đạo các\nquy trình vệ sinh và khử trùng môi trường. Vệ sinh môi trường thường xuyên bao gồm vệ sinh hàng\nngày các khu vực sau:\n• Đơn vị điều dưỡng, phòng bệnh nhân và các khu vực chăm sóc bệnh nhân khác\n• Địa điểm chẩn đoán và điều trị\n• Khu vực dịch vụ hỗ trợ chung, chẳng hạn như cung cấp trung tâm, dịch vụ khăn trải giường, quản lý\nvật liệu và tất cả các khoa và khu vực khác của bệnh viện\n• Khu vực chờ và các không gian công cộng khác\n• Không gian làm việc của nhân viên\n• Bếp\n\nVệ sinh đầu cuối là quy trình vệ sinh tập trung và kỹ lưỡng hơn so với vệ sinh bảo dưỡng hàng ngày\nvà được thực hiện theo các chính sách và quy trình của bệnh viện cũng như các hướng dẫn kiểm soát\nnhiễm trùng. Bệnh viện phải xác định cách thức, thời điểm và địa điểm thực hiện vệ sinh đầu cuối.\nQuy trình có thể khác nhau tùy thuộc vào khu vực được vệ sinh đầu cuối. Ví dụ, vệ sinh phòng sau\nkhi bệnh nhân xuất viện theo các biện pháp phòng ngừa cách ly đối với bệnh truyền nhiễm có thể\nyêu cầu các quy trình và chất tẩy rửa khác so với vệ sinh đầu cuối của phòng phẫu thuật hoặc các\nkhoa cung cấp vô trùng trung tâm. Việc vệ sinh cuối cùng đòi hỏi phải chú ý hơn đến môi trường và\ncó thể bao gồm các nội dung sau:\n• Giặt rèm riêng tư\n• Tháo và vệ sinh tất cả các vật dụng có thể tháo rời trong phòng\n• Khử trùng bề mặt bằng nhiều chất tẩy rửa\n• Sử dụng các công cụ chuyên dụng như máy khử trùng bằng tia cực tím hoặc máy ozone\n\nMột số khu vực của bệnh viện cần được chú ý thêm trong quá trình vệ sinh và khử trùng môi trường do bản chất\nrủi ro cao của chúng. Các nhà lãnh đạo bệnh viện tiến hành đánh giá rủi ro để xác định khu vực nào của bệnh viện\ncần được vệ sinh và khử trùng thêm. Các nhà lãnh đạo bệnh viện xác định các hướng dẫn và khuyến nghị thực\nhành phù hợp để nhân viên sử dụng khi vệ sinh và khử trùng các khu vực hoặc tình huống có rủi ro cao và nhân\nviên được đào tạo về các quy trình vệ sinh và cách sử dụng an toàn các chất tẩy rửa. Bệnh viện cũng phải đánh giá\nxem có bất kỳ khu vực hoặc bề mặt sạch quan trọng hoặc quan trọng nào nằm trong phạm vi 1 mét tính từ bồn\nrửa hay không, vì điều này gây ra nguy cơ ô nhiễm do nước bắn vào. Ví dụ, mặt bàn trong phòng thuốc được sử\ndụng để pha chế thuốc đơn giản trước khi dùng thuốc phải được bảo vệ khỏi nước bắn vào nếu nằm trong phạm\nvi 1 mét tính từ bồn rửa. Bệnh viện phải xác định cách ngăn ngừa ô nhiễm, chẳng hạn như lắp đặt tấm chắn giữa\nbồn rửa và mặt bàn hoặc di chuyển khu vực được sử dụng để pha chế thuốc.\n\nHiệu quả vệ sinh và khử trùng môi trường phải được theo dõi. Bệnh viện xác định cách thực hiện giám sát này\ndựa trên các nguồn lực và công nghệ sẵn có. Dữ liệu từ quá trình giám sát được sử dụng để đánh giá các quy trình\nvệ sinh và khử trùng và chỉ đạo mọi thay đổi cần thiết để đảm bảo môi trường sạch sẽ. Những dữ liệu này cũng\nđược sử dụng trong quá trình giáo dục với nhân viên vệ sinh môi trường.\n\nBệnh viện xác định các hoạt động vệ sinh thường xuyên của mình, bao gồm:\n•\nTần suất vệ sinh thường xuyên, bao gồm các bề mặt thường xuyên tiếp xúc\n•\nKhi nào cần vệ sinh đầu cuối\n•\nCần thực hiện các hoạt động vệ sinh và khử trùng bổ sung nào cho các khu vực có nguy cơ cao\n•\nCần thực hiện các hoạt động vệ sinh và khử trùng bổ sung nào cho các khu vực chăm sóc bệnh nhân truyền\nnhiễm\n•\nThiết bị và tác nhân vệ sinh được sử dụng\n•\nNhân viên nào chịu trách nhiệm vệ sinh\n•\nKhi nào cần vệ sinh thường xuyên hơn\n\nBệnh viện xác định những khu vực nào được coi là có nguy cơ cao đối với các quy trình vệ sinh và khử trùng và\nthực hiện khử trùng cấp độ thấp hoặc khử trùng cấp độ trung gian một cách phù hợp. Ví dụ về các khu vực có\nnguy cơ cao bao gồm:\n•\nPhòng phẫu thuật\n•\nKhoa cung cấp vô trùng trung tâm\n•\nKhoa chăm sóc tích cực sơ sinh\n•\nKhoa bỏng\n•\nKhu vực chăm sóc bệnh nhân nhiễm trùng\n\nDữ liệu giám sát có thể được thu thập bằng nhiều phương pháp khác nhau, bao gồm các ví dụ sau:\n•\nNhận xét của bệnh nhân và gia đình cũng như dữ liệu về trải nghiệm của bệnh nhân, chẳng hạn như độ sạch của\nphòng và độ sạch chung của bệnh viện\n•\nCó thể sử dụng các dấu hiệu huỳnh quang và phát quang sinh học adenosine triphosphate (ATP) để kiểm tra các\nmầm bệnh còn sót lại.\n•\nQuan sát trực tiếp các quy trình vệ sinh và khử trùng\n\nCác yếu tố đo lường được của PCI.04.00\n1.\nChương trình phòng ngừa và kiểm soát nhiễm trùng thực hiện các hướng dẫn và quy trình vệ sinh và\nkhử trùng dựa trên bằng chứng trên toàn bộ bệnh viện. (Xem thêm MMU.05.00, ME 2)\n2.\nCác hướng dẫn dựa trên bằng chứng được sử dụng để chỉ đạo các quy trình vệ sinh và khử trùng tại các\nkhu vực có nguy cơ cao theo chỉ định của các tiêu chuẩn vệ sinh và khử trùng dựa trên bằng chứng. (Xem\nthêm MMU.05.00, ME 2)\n3.\nCác hướng dẫn dựa trên bằng chứng được sử dụng để chỉ đạo vệ sinh và khử trùng các khu vực nơi\nbệnh nhân mắc bệnh truyền nhiễm được chăm sóc, bao gồm cả sau khi bệnh nhân xuất viện.\n4.\nBệnh viện giám sát các quy trình vệ sinh và khử trùng môi trường và dữ liệu được sử dụng để thực hiện\ncác thay đổi đối với quy trình khi áp dụng.","m":[],"sec":"Vệ sinh môi trường"},{"c":"PCI.04.01","ch":"PCI","t":"Chương trình phòng ngừa và kiểm soát nhiễm trùng tuân theo các hướng dẫn dựa trên bằng chứng liên quan đến việc vệ sinh và khử trùng đồ giặt, khăn trải giường và trang phục phẫu thuật do bệnh viện cung cấp.","p":"Các phương pháp giặt tuân thủ luật pháp và quy định của địa phương và quốc gia và tuân theo hướng dẫn\ntừ các cơ quan kiểm soát nhiễm trùng được công nhận để đảm bảo xử lý an toàn và kỹ lưỡng đồ giặt, khăn\ntrải giường và quần áo phẫu thuật do bệnh viện cung cấp. Việc xử lý đồ giặt, khăn trải giường và quần áo\nphẫu thuật do bệnh viện cấp bao gồm các quy trình sau:\n• Thu gom\n• Phân loại\n• Giặt\n• Sấy\n• Gấp\n• Phân phối\n• Lưu trữ\n\nNhân viên xử lý đồ giặt, khăn trải giường và quần áo phẫu thuật tuân theo các biện pháp phòng ngừa tiêu\nchuẩn và sử dụng các biện pháp phòng ngừa phù hợp dựa trên khả năng lây truyền khi xử lý đồ giặt và khăn\ntrải giường từ phòng cách ly. Đồ giặt, khăn trải giường và quần áo phẫu thuật do bệnh viện cấp bị nhiễm\nbẩn bị thấm máu hoặc các chất dịch cơ thể khác được tách riêng khỏi các vật dụng bị bẩn khác và được dán\nnhãn là bị nhiễm bẩn để cảnh báo nhân viên về nguy cơ nhiễm trùng gia tăng.\n\nGiặt giũ tuân theo các hướng dẫn của các cơ quan kiểm soát nhiễm trùng, bao gồm:\n• Nhiệt độ nước\n• Thời gian giặt\n• Sử dụng chất tẩy rửa, chẳng hạn như thuốc tẩy và chất tẩy rửa\n• Bảo quản, xử lý và vận chuyển các vật dụng đã giặt sạch\n\nĐồ giặt, khăn trải giường và quần áo phẫu thuật do bệnh viện cấp được xử lý, vận chuyển và lưu trữ theo\ncách ngăn ngừa lây nhiễm chéo giữa các vật dụng bẩn và sạch. Khi giặt giũ được thực hiện bên ngoài bệnh\nviện bởi một nhà thầu, bệnh viện phải có phương tiện để giám sát chất lượng dịch vụ (xem thêm Tiêu\nchuẩn GLD.05.00).\n\nBệnh viện xác định các khu vực mà nhân viên được yêu cầu mặc quần áo phẫu thuật do bệnh viện cấp, bao\ngồm áo khoác hoặc áo khoác trắng (ví dụ: Khoa cung cấp vật tư vô trùng trung tâm, phòng phẫu thuật, khoa\nchăm sóc tích cực sơ sinh). Bệnh viện cũng thực hiện các biện pháp làm giảm nguy cơ nhiễm trùng liên\nquan đến áo khoác trắng và áo khoác phòng thí nghiệm. Nhân viên được đào tạo về thời điểm thay quần áo\nphẫu thuật và thời điểm họ phải che hoặc thay bộ quần áo phẫu thuật. Nhân viên không được cung cấp\ntrang phục phẫu thuật do bệnh viện cấp sẽ được đào tạo về các biện pháp giặt giũ tại nhà để giảm thiểu\nnguy cơ lây nhiễm giữa bệnh viện và cộng đồng.\n\nCác yếu tố đo lường được của PCI.04.01\n1.\nCác phương pháp giặt là tuân thủ luật pháp và quy định của địa phương và quốc gia và tuân theo\nhướng dẫn của các cơ quan kiểm soát nhiễm trùng được công nhận.\n2.\nCác biện pháp phòng ngừa tiêu chuẩn được sử dụng khi xử lý đồ giặt, khăn trải giường và quần\náo phẫu thuật do bệnh viện cấp, và các biện pháp phòng ngừa dựa trên lây truyền thích hợp được\nsử dụng theo chỉ định của rủi ro nhiễm trùng.\n3.\nĐồ giặt, khăn trải giường và quần áo phẫu thuật do bệnh viện cấp được vận chuyển, xử lý và lưu\ntrữ theo cách ngăn ngừa lây nhiễm chéo giữa các vật dụng bẩn và sạch.\n4.\nNhân viên mặc quần áo phẫu thuật sạch do bệnh viện cấp ở những khu vực quan trọng do bệnh\nviện xác định, theo tiêu chuẩn kiểm soát nhiễm trùng hiện hành, tiêu chuẩn của ngành chăm sóc\nsức khỏe quốc gia và chính sách của bệnh viện.\n\nMô và chất thải truyền nhiễm của con người","m":[]},{"c":"PCI.05.00","ch":"PCI","t":"Bệnh viện thực hiện các quy trình xử lý chất thải đúng cách, quản lý đúng cách các mô của con người và xử lý và thải bỏ an toàn các vật sắc nhọn và kim tiêm.","p":"Bệnh viện thải ra một lượng rác thải đáng kể mỗi ngày. Thường thì rác thải đó là hoặc có thể là chất lây nhiễm.\nDo đó, việc xử lý rác thải đúng cách, quản lý đúng cách các mô của con người và xử lý và tiêu hủy an toàn các\nvật sắc nhọn và kim tiêm góp phần làm giảm nguy cơ lây nhiễm trong bệnh viện. Điều này đúng đối với việc xử\nlý chất dịch cơ thể và vật liệu bị nhiễm chất dịch cơ thể, xử lý máu và các thành phần máu, và xử lý hoặc tiêu\nhủy chất thải bệnh lý. Các mô, cơ quan và bộ phận cơ thể của con người cần được quản lý cẩn thận và tôn\ntrọng để giảm nguy cơ nhiễm trùng trong quá trình xử lý, vận chuyển và chế biến.\n\nBệnh viện cũng phải ngăn ngừa chất thải truyền nhiễm làm ô nhiễm môi trường và lây truyền bệnh ra bên\nngoài bệnh viện. Các vật liệu bị nhiễm chất dịch cơ thể, máu và các thành phần máu, và chất thải bệnh lý tạo ra\nnguy cơ lây nhiễm cho nhân viên xử lý và tiêu hủy chúng.\n\nMột trong những nguy cơ của thương tích do kim tiêm và vật sắc nhọn là khả năng lây truyền các bệnh qua\nđường máu. Xử lý và tiêu hủy vật sắc nhọn và kim tiêm không đúng cách gây ra mối nguy hiểm lớn cho sự an\ntoàn của nhân viên. Các phương pháp làm việc ảnh hưởng đến nguy cơ thương tích và khả năng tiếp xúc với\nbệnh tật. Việc xác định và thực hiện các biện pháp dựa trên bằng chứng để giảm nguy cơ thương tích do vật\nsắc nhọn đảm bảo rằng việc tiếp xúc với những thương tích như vậy là tối thiểu. Các bệnh viện cần cung cấp\ncho nhân viên chương trình giáo dục liên quan đến việc xử lý và quản lý vật sắc nhọn và kim tiêm an toàn.\n\nViệc vứt bỏ kim tiêm và vật sắc nhọn đúng cách cũng làm giảm nguy cơ thương tích và tiếp xúc. Việc vứt bỏ\nđúng cách bao gồm việc sử dụng các thùng chứa có thể đóng lại, chống thủng và chống rò rỉ ở hai bên và đáy.\nCác thùng chứa phải dễ dàng tiếp cận đối với nhân viên và không được chứa quá đầy. Ngoài ra, các thùng chứa\nphải được dán nhãn để cảnh báo về nguy cơ thương tích tiềm ẩn và được cất giữ để tránh vật sắc nhọn tràn ra\nkhỏi thùng chứa.\n\nViệc vứt bỏ không đúng cách các loại kim tiêm, dao mổ và các vật sắc nhọn khác đã qua sử dụng có thể gây ra\nrủi ro sức khỏe cho cộng đồng và những người làm việc trong lĩnh vực quản lý chất thải. Ví dụ, việc vứt bỏ các\nthùng chứa vật sắc nhọn ở đại dương hoặc trong chất thải nói chung có thể gây ra rủi ro cho cộng đồng nếu các\nthùng chứa bị vỡ. Các bệnh viện phải vứt bỏ vật sắc nhọn và kim tiêm một cách an toàn hoặc ký hợp đồng với\ncác tổ chức đảm bảo việc vứt bỏ đúng cách các thùng chứa chất thải y tế theo luật định.\n\nBệnh viện thực hiện chính sách giải quyết thỏa đáng tất cả các bước trong quy trình, bao gồm xác định loại và\ncách sử dụng thùng chứa phù hợp, việc xử lý thùng chứa và giám sát quy trình xử lý.\n\nCó những cân nhắc đặc biệt liên quan đến việc xử lý an toàn và tôn trọng người đã khuất và các bộ phận cơ thể\nngười. Nhà xác được xây dựng theo cách đảm bảo an toàn cho các thi thể và bộ phận cơ thể cũng như sự an\ntoàn của nhân viên xử lý chúng. Lãnh đạo bệnh viện tham khảo luật pháp và quy định của địa phương và quốc\ngia và xem xét các nền văn hóa và phong tục địa phương khi thiết kế nhà xác bệnh viện. Những cân nhắc bổ\nsung bao gồm cách đảm bảo chuỗi lưu giữ đối với các thi thể, bộ phận cơ thể và bất kỳ mẫu vật nào được lấy\nra để xét nghiệm; cách thông báo cho nhân viên về tình trạng nhiễm trùng đã biết hoặc nghi ngờ; và cách bảo\nquản các thi thể để ngăn ngừa khả năng lây nhiễm chéo. Ví dụ, một chuỗi lưu giữ phù hợp quy định rằng bệnh\nviện có phương tiện bảo vệ thi thể hoặc các bộ phận cơ thể cho đến khi chúng không còn thuộc thẩm quyền\ncủa bệnh viện và hồ sơ về vấn đề này. Nhà xác cũng được duy trì ở nhiệt độ và độ ẩm đảm bảo lưu trữ đúng\ncách. Nhân viên được tiếp cận với thiết bị bảo vệ cá nhân, trạm rửa tay và các chất tẩy rửa cần thiết trong toàn\nbộ nhà xác và được đào tạo về các quy trình xử lý an toàn, tôn trọng.\n\nCác yếu tố đo lường được của PCI.05.00\n1.\nBệnh viện thực hiện các biện pháp nhằm giảm nguy cơ nhiễm trùng từ việc xử lý và thải bỏ chất thải\ntruyền nhiễm, máu và các thành phần máu, dịch cơ thể và mô cơ thể. (Xem thêm FMS.05.00, ME 2)\n2.\nBệnh viện xác định và thực hiện các biện pháp nhằm giảm nguy cơ thương tích và nhiễm trùng từ việc\nxử lý và quản lý vật sắc nhọn và kim tiêm.\n3.\nVật sắc nhọn và kim tiêm được thu gom trong các thùng chứa chuyên dụng, có thể đóng lại, chống đâm\nthủng, chống rò rỉ và không được tái sử dụng.\n4.\nBệnh viện xử lý vật sắc nhọn và kim tiêm một cách an toàn hoặc ký hợp đồng với các nhà cung cấp đảm\nbảo xử lý đúng cách các thùng chứa vật sắc nhọn tại các bãi chôn lấp chất thải nguy hại chuyên dụng hoặc\ntheo quy định của luật pháp và quy định quốc gia.\n5.\nKhu vực nhà xác và khám nghiệm tử thi hoạt động theo cách tuân thủ luật pháp, quy định và văn hóa/phong\ntục địa phương và được quản lý theo cách giảm thiểu nguy cơ lây nhiễm.\n6.\nNhân viên được đào tạo về việc ngăn ngừa lây nhiễm chéo, duy trì chuỗi lưu ký khi cần thiết và các quy\ntrình xử lý an toàn, tôn trọng tại các khu vực khám nghiệm tử thi.\n7.\nBệnh viện có chính sách bằng văn bản để chỉ đạo chuỗi lưu giữ đối với tất cả các thi thể và bộ phận cơ\nthể được xử lý bởi khoa bệnh học, nhà xác và các khu vực sau khi chết khác.","m":[],"sec":"Mô và chất thải truyền nhiễm của con người"},{"c":"PCI.05.01","ch":"PCI","t":"Bệnh viện làm giảm nguy cơ nhiễm trùng liên quan đến việc tiếp xúc với máu, dịch cơ thể và các vật liệu có khả năng lây nhiễm khác.","p":"Bệnh nhân, khách thăm, nhân viên và bác sĩ có nguy cơ tiếp xúc với các tác nhân gây bệnh qua đường máu khi có mặt tại\nbệnh viện hoặc khi thực hiện nhiệm vụ của mình tại bệnh viện. Tiếp xúc với các tác nhân gây bệnh qua đường máu tiềm\nẩn xảy ra khi bác sĩ, nhân viên, bệnh nhân hoặc khách thăm tiếp xúc với máu hoặc dịch cơ thể của người khác qua da không\nnguyên vẹn, niêm mạc, mắt, mũi hoặc miệng.\nNhiều tác nhân gây bệnh khác nhau, bao gồm viêm gan B, viêm gan C và HIV, có thể lây truyền qua tiếp xúc với máu hoặc\ndịch cơ thể. Các dịch cơ thể bao gồm dịch não tủy, dịch hoạt dịch, dịch màng phổi, dịch phúc mạc, dịch màng ngoài tim,\ndịch tinh dịch và dịch ối. Các dịch cơ thể khác không mang nguy cơ lây truyền tác nhân gây bệnh qua đường máu trừ khi\ncó thể nhìn thấy bằng mắt thường bị nhiễm máu bao gồm sữa mẹ, đờm, dịch tiết mũi, nước bọt, mồ hôi, nước mắt,\nnước tiểu, phân và nôn mửa; việc tiếp xúc với các dịch này thường không cần phải báo cáo hoặc theo dõi trừ khi có thể\nnhìn thấy bằng mắt thường bị nhiễm máu hoặc nếu luật pháp và quy định của địa phương hoặc quốc gia hoặc chính sách\ncủa bệnh viện yêu cầu. Sử dụng đúng thiết bị bảo vệ cá nhân phù hợp với nhiệm vụ có thể làm giảm đáng kể khả năng\nphơi nhiễm. Bệnh viện phải cung cấp đủ nguồn lực như thiết bị bảo vệ cá nhân phù hợp và thiết bị an toàn, khi có thể,\ncho nhân viên có thể tiếp xúc với máu và dịch cơ thể trong khi thực hiện nhiệm vụ của mình.\n\nBệnh viện thiết lập quy trình xử lý tình trạng phơi nhiễm máu và dịch cơ thể của nhân viên, bệnh nhân và khách đến thăm.\nQuy trình bao gồm việc báo cáo sự cố cho ai. Quy trình này có thể thay đổi tùy thuộc vào thời gian trong ngày hoặc ngày\ntrong tuần; tuy nhiên, nhân viên phải có khả năng báo cáo sự cố phơi nhiễm bất cứ lúc nào xảy ra. Quy trình bao gồm báo\ncáo sự cố cho người giám sát trực tiếp và cho bộ phận y tế của nhân viên hoặc khoa cấp cứu. Điều này đảm bảo ghi chép\nvà phản hồi sự cố kịp thời. Quy trình cũng xác định các yêu cầu hành động để ứng phó sau khi tiếp xúc với máu hoặc dịch\ncơ thể. Các hành động này tuân thủ luật pháp địa phương và quốc gia, cũng như các khuyến nghị và hướng dẫn từ các tổ\nchức kiểm soát nhiễm trùng, bao gồm cách vệ sinh và/hoặc khử trùng khu vực bị phơi nhiễm, xét nghiệm nào để phát hiện\ncác bệnh lây truyền qua đường máu và liệu có nên bắt đầu liệu pháp dự phòng sau phơi nhiễm hay không. Quy trình này\ncũng bao gồm các bước thông báo cho bất kỳ bệnh nhân nào có liên quan đến việc tiếp xúc, khi thích hợp, và các điều\nkhoản để xét nghiệm các bệnh nhân có liên quan về các bệnh nhiễm trùng qua đường máu riêng biệt với việc chăm sóc\nbệnh nhân.\n\nDữ liệu từ các sự cố phơi nhiễm được theo dõi và giám sát, và các báo cáo sự cố phơi nhiễm được nhân viên có\nthẩm quyền xem xét và báo cáo cho các nhà lãnh đạo bệnh viện. Thông tin từ các báo cáo sự cố được sử dụng để\nđánh giá các quy trình góp phần gây ra hoặc gây ra sự cố phơi nhiễm máu hoặc dịch cơ thể, và các thay đổi được\nthực hiện để giảm khả năng xảy ra sự cố lặp lại. Nhân viên được giáo dục về những thay đổi này.\n\nCác yếu tố đo lường được của PCI.05.01\n1.\nBệnh viện xác định các quy trình có thể dẫn đến việc bệnh nhân hoặc nhân viên tiếp xúc với máu và dịch cơ thể.\n2.\nBệnh viện thực hiện các biện pháp để giảm nguy cơ tiếp xúc với máu và dịch cơ thể.\n3.\nBệnh viện sử dụng quy trình nhanh chóng để báo cáo kịp thời tình trạng bệnh nhân, nhân viên và khách tiếp xúc\nvới máu và dịch cơ thể.\n4.\nBệnh viện sử dụng quy trình để xử lý tình trạng bệnh nhân, nhân viên và khách tiếp xúc với máu và dịch cơ thể.\n5.\nNhân viên được đào tạo về quy trình báo cáo sự cố tiếp xúc.\n6.\nBệnh viện theo dõi và giám sát các sự cố bệnh nhân và nhân viên tiếp xúc với máu và dịch cơ thể.\n7.\nCác báo cáo về sự cố tiếp xúc được xem xét và các hành động được thực hiện để giảm thiểu nguy cơ tiếp xúc với\nmáu và dịch cơ thể trong tương lai\n\nDịch vụ thực phẩm","m":[]},{"c":"PCI.06.00","ch":"PCI","t":"Bệnh viện giảm nguy cơ nhiễm trùng liên quan đến hoạt động của các dịch vụ thực phẩm và chế độ ăn kiêng.","p":"Thực phẩm được bảo quản và chế biến không đúng cách có thể gây ra bệnh tật, thông qua việc lây truyền mầm bệnh\ndo nhân viên xử lý và chế biến thực phẩm hoặc thông qua vi sinh vật trong thực phẩm. Bệnh tật do thực phẩm có thể\nnguy hiểm và thậm chí đe dọa đến tính mạng đối với bệnh nhân nằm viện có tình trạng bệnh đã xấu đi do bệnh tật\nhoặc chấn thương. Bệnh viện phải cung cấp thực phẩm và các sản phẩm dinh dưỡng an toàn và chính xác bằng cách\nđảm bảo thực phẩm được bảo quản, chế biến và vận chuyển theo cách ngăn ngừa sự lây truyền mầm bệnh và ở nhiệt\nđộ ngăn ngừa nguy cơ phát triển của vi khuẩn.\n\nLãnh đạo bệnh viện phải hiểu chuỗi cung ứng thực phẩm từ đầu đến cuối để đảm bảo hoạt động an toàn của các dịch\nvụ thực phẩm. Lãnh đạo bệnh viện cũng phải hiểu cách quản lý bệnh tật của nhân viên theo các chính sách và quy trình\ncủa bệnh viện, hướng dẫn dựa trên bằng chứng và luật pháp và quy định hiện hành để tránh\nlây truyền bệnh tật như viêm gan A và các mầm bệnh khác có thể lây truyền qua nhân viên thông qua việc xử lý thực\nphẩm, vì lãnh đạo chịu trách nhiệm cuối cùng trong việc đảm bảo các quy trình này được tuân thủ nhất quán.\n\nBệnh viện phải đảm bảo lựa chọn cẩn thận các nguồn thực phẩm và nhà cung cấp, cũng như quy trình bảo quản, xử\nlý và chế biến thực phẩm an toàn. Phải có một quy trình để đảm bảo tính toàn vẹn của chuỗi cung ứng thực phẩm;\nbao gồm sự ổn định nhiệt độ trong quá trình vận chuyển đến bệnh viện, các cơ chế ngăn ngừa thực phẩm bị can thiệp\nvà các thùng chứa lưu trữ thích hợp trong quá trình vận chuyển. Bệnh viện phải đảm bảo nhiệt độ thích hợp của thực\nphẩm đã chế biến trong quá trình vận chuyển từ bếp đến bệnh nhân. Điều này có thể được thực hiện theo nhiều cách;\nví dụ, nhân viên bếp có thể tiến hành kiểm tra ngẫu nhiên và kiểm tra nhiệt độ của một số bữa ăn khi chúng rời khỏi\nbếp và trước khi được phục vụ cho bệnh nhân. Cũng phải có một quy trình để đảm bảo rằng thực phẩm không bị để\nbên ngoài trong một khoảng thời gian khiến thực phẩm không phù hợp để tiêu thụ. Ví dụ, bệnh viện phải đảm bảo\nrằng thực phẩm nóng và lạnh đang chờ tiêu thụ phải được duy trì ở nhiệt độ an toàn trong suốt thời gian phục vụ.\nViệc bảo quản thực phẩm an toàn phải bao gồm việc duy trì các mặt hàng ở nhiệt độ thích hợp và bảo vệ khỏi sự xâm\nnhập của sâu bệnh, và có thể bao gồm việc tuân thủ các nguyên tắc như nhập trước, xuất trước (FIFO), giúp đảm bảo\nrằng thực phẩm được sử dụng trước ngày hết hạn. Một hệ thống luân chuyển thực phẩm hiệu quả là điều cần thiết\nđể bảo quản thực phẩm nhằm ngăn ngừa bệnh do thực phẩm.\n\nNhiễm chéo, đặc biệt là từ thực phẩm sống sang thực phẩm chín, là một nguồn khác gây ra bệnh do thực phẩm;\ncác nhà lãnh đạo bệnh viện thực hiện các biện pháp để giảm thiểu rủi ro này và đảm bảo rằng bất kỳ nhà cung\ncấp và người bán nào cũng thực hiện như vậy. Ngoài việc trộn lẫn thực phẩm sống và thực phẩm chế biến,\nnhiễm chéo có thể xảy ra do tay bị nhiễm bẩn, bề mặt chế biến thực phẩm như mặt bàn bếp và thớt, hoặc\nkhăn lau mặt bàn bếp hoặc lau khô bát đĩa. Các dụng cụ, thiết bị, nồi và chảo dùng để chế biến thực phẩm,\ncũng như khay, bát đĩa và dụng cụ dùng để phục vụ thực phẩm cũng có thể gây nguy cơ nhiễm trùng nếu không\nđược vệ sinh và khử trùng đúng cách. Nhân viên bị bệnh hoặc không thực hiện vệ sinh tay đúng cách cũng có\nthể lây nhiễm khi chế biến thực phẩm. Bệnh viện phải có quy trình, bao gồm các chính sách và thủ tục, để đảm\nbảo rằng nhân viên bị bệnh không chế biến thực phẩm. Bệnh viện tiến hành đánh giá rủi ro khi thực phẩm\nđược lưu trữ hoặc chế biến bên ngoài khu vực bếp trung tâm, bao gồm tủ lạnh của bệnh nhân và thực hiện các\ngiao thức để giảm thiểu rủi ro liên quan đến hoạt động này.\n\nMột số sản phẩm dinh dưỡng, chẳng hạn như sữa mẹ, sữa công thức cho trẻ em và các sản phẩm dinh dưỡng\nđường ruột khác, có yêu cầu bảo quản và chế biến đặc biệt. Nhân viên tham khảo các hướng dẫn chuyên môn\nđể xác định tiêu chí xử lý an toàn cho các sản phẩm này, bao gồm nhiệt độ bảo quản, thời gian bảo quản, kỹ\nthuật chế biến, dán nhãn phù hợp và hướng dẫn quản lý.\n\nChương trình thực phẩm và dinh dưỡng phải được tích hợp với chương trình phòng ngừa và kiểm soát nhiễm\ntrùng và chương trình sức khỏe của nhân viên.\n\nCác yếu tố đo lường được của PCI.06.00\n1.\nBệnh viện lưu trữ thực phẩm và các sản phẩm dinh dưỡng theo cách làm giảm nguy cơ nhiễm trùng, bao gồm\ncả những sản phẩm được lưu trữ bên ngoài bếp và khu vực chế biến thực phẩm.\n2.\nBệnh viện áp dụng và thực hiện các biện pháp vệ sinh bếp và hướng dẫn cho khu vực chế biến để ngăn ngừa\nnguy cơ lây nhiễm chéo và nhiễm trùng.\n3.\nBệnh viện chế biến thực phẩm và các sản phẩm dinh dưỡng bằng cách sử dụng nhiệt độ và vệ sinh thích hợp.\n4.\nBệnh viện sử dụng một quy trình để đảm bảo duy trì nhiệt độ thực phẩm thích hợp trong quá trình chế biến,\nvận chuyển và phân phối.\n5.\nCác hướng dẫn chuyên môn được áp dụng cho các sản phẩm dinh dưỡng có yêu cầu bảo quản và chế biến\nđặc biệt, chẳng hạn như sữa mẹ, sữa công thức cho trẻ em và các sản phẩm đường ruột khác\n\nLây truyền bệnh truyền nhiễm","m":[],"sec":"Dịch vụ thực phẩm"},{"c":"PCI.07.00","ch":"PCI","t":"Bệnh viện bảo vệ bệnh nhân, khách thăm và nhân viên khỏi sự lây truyền các bệnh truyền nhiễm và nhiễm trùng.","p":"Ngoài việc sử dụng các biện pháp phòng ngừa tiêu chuẩn, phải sử dụng các biện pháp phòng ngừa dựa trên đường\ntruyền để ngăn ngừa lây truyền nhiễm trùng dựa trên loại vi sinh vật (ví dụ, sử dụng phòng áp suất âm và khẩu\ntrang N95 cho các bệnh truyền nhiễm qua không khí). Các biện pháp phòng ngừa dựa trên đường truyền bao gồm\ntất cả các phương thức lây truyền tiềm ẩn, chẳng hạn như tiếp xúc, giọt bắn và không khí. Chúng cũng bao gồm\ncác cân nhắc đặc biệt như các biện pháp phòng ngừa Clostridioides difficile. Các tác nhân gây bệnh lây truyền\nqua không khí như bệnh lao và COVID-19 cần các phòng cách ly áp suất không khí âm để ngăn ngừa lây truyền\nvì các tác nhân gây bệnh này có thể lơ lửng trong không khí trong thời gian dài. (Để biết thêm các cân nhắc liên\nquan đến các bệnh mới nổi hoặc mới có ý nghĩa quan trọng như COVID-19, hãy xem","m":[],"sec":"Lây truyền bệnh truyền nhiễm"},{"c":"PCI.07.01","ch":"PCI","t":"Bệnh viện cung cấp các nguồn lực và thiết bị để bảo vệ nhân viên, bác sĩ, bệnh nhân và khách thăm khỏi các mối nguy sinh học, vật lý và hóa học, và chúng luôn sẵn sàng để sử dụng.","p":"Vệ sinh tay (như sử dụng chất khử trùng), kỹ thuật rào cản (như sử dụng thiết bị bảo vệ cá nhân) và chất khử\ntrùng là những công cụ cơ bản để phòng ngừa và kiểm soát nhiễm trùng đúng cách và do đó cần phải có sẵn tại\nbất kỳ địa điểm chăm sóc nào có thể cần đến chúng, bao gồm phòng thí nghiệm, các khu vực khác nơi xử lý\nmẫu vật và cơ sở giặt là. Nhân viên và bác sĩ phải sử dụng thiết bị bảo vệ cá nhân phù hợp khi được chỉ định,\ntheo luật pháp và quy định cũng như các hướng dẫn kiểm soát nhiễm trùng hiện hành và sử dụng các phương\npháp vệ sinh tay phù hợp khi được chỉ định. Ví dụ bao gồm đeo găng tay và tấm chắn mặt khi hút dịch cho\nbệnh nhân hoặc sử dụng găng tay, áo choàng, tấm chắn mặt và khẩu trang phù hợp như N95 hoặc máy lọc\nkhông khí có trợ lực (PAPR) cho bệnh nhân đang cách ly do mắc bệnh truyền nhiễm và thực hiện vệ sinh tay\ntrước và sau khi chăm sóc bệnh nhân.\n\nBệnh viện xác định những tình huống cần sử dụng thiết bị bảo vệ cá nhân như máy thở, khẩu trang, đồ bảo\nvệ mắt, áo choàng hoặc găng tay để bảo vệ chống lại các mối nguy sinh học, bao gồm các tác nhân gây bệnh có\nnguy cơ cao cần các biện pháp phòng ngừa cách ly đặc biệt như khẩu trang N95, PAPR hoặc áo choàng bảo vệ\ncấp cao hơn; cung cấp các thiết bị cần thiết; và đào tạo nhân viên và bác sĩ về cách sử dụng đúng cách. Xà phòng\nlỏng và nước, chất khử trùng tay gốc cồn và các chất khử trùng thích hợp khác được đặt ở những khu vực yêu\ncầu rửa tay và khử trùng tay. Khi cần thiết bị bảo vệ cá nhân, chúng luôn sẵn sàng để sử dụng. Điều quan trọng\nlà phải tuân theo các hướng dẫn để đảm bảo bình đựng xà phòng lỏng được vệ sinh kỹ lưỡng và đúng cách\ntrước khi nạp lại. Nhân viên được đào tạo về các quy trình rửa tay, khử trùng tay và khử trùng bề mặt đúng\ncách và cách sử dụng đúng thiết bị bảo vệ cá nhân. Bệnh nhân và khách thăm cũng được đào tạo về các quy\ntrình khử trùng tay đúng cách và khi nào họ được yêu cầu sử dụng thiết bị bảo vệ cá nhân; ví dụ, khi đến thăm\nmột thành viên gia đình đang cách ly tiếp xúc hoặc khi một bệnh nhân đang áp dụng các biện pháp phòng ngừa\nlây truyền qua không khí được vận chuyển qua tổ chức.\n\nCác yếu tố đo lường được của PCI.07.01\n1.\nBệnh viện xác định các tình huống cần có thiết bị bảo vệ cá nhân.\n2.\nBệnh viện đảm bảo rằng thiết bị bảo vệ cá nhân và chất vệ sinh tay phù hợp luôn sẵn sàng khi cần. (Xem thêm\nIPSG.05.00, MEs 1 và 2; FMS.09.01, ME 1)\n3.\nNhân viên được đào tạo và sử dụng đúng thiết bị bảo vệ cá nhân trong từng tình huống đã xác định.\n4.\nBệnh viện thực hiện các quy trình khử trùng môi trường cho các khu vực và tình huống trong bệnh viện\nđược xác định là có nguy cơ lây truyền nhiễm trùng.\n5.\nXà phòng lỏng và nước máy, chất khử trùng tay và khăn dùng một lần được cung cấp ở những khu vực\ncần thực hiện quy trình rửa tay và khử trùng tay, và không sử dụng máy sấy tay trong khu vực chăm sóc\nbệnh nhân. (Xem thêm IPSG.05.00, MEs 1 và 2)\n6.\nBệnh nhân và khách thăm được giáo dục về thời điểm họ cần khử trùng tay, khi nào phải tuân thủ các biện\npháp phòng ngừa lây truyền như biện pháp phòng ngừa cách ly và cách sử dụng đúng thiết bị bảo vệ cá nhân\nkhi áp dụng. (Xem thêm IPSG.05.00, MEs 1 và 2)","m":[]},{"c":"PCI.07.02","ch":"PCI","t":"Bệnh viện thực hiện các quy trình để hỗ trợ công tác chuẩn bị cho các bệnh truyền nhiễm có ý nghĩa về mặt dịch tễ học hoặc các tác nhân gây bệnh đặc biệt. 266 Prevention and Control of Infections (PCI) PreventIon and Control of InfeCtIonS (PCI).","p":"Các bệnh truyền nhiễm có hậu quả nghiêm trọng hoặc các tác nhân gây bệnh đặc biệt là các bệnh truyền nhiễm hoặc\ntác nhân gây bệnh mới và tái phát có khả năng lây truyền cao từ người sang người (hoặc có phương thức lây truyền\nchưa xác định) và có khả năng gây ra dịch bệnh hoặc đại dịch với tỷ lệ mắc bệnh và tử vong cao. Tiêu chuẩn này đề\ncập đến các bệnh mới nổi có ý nghĩa quan trọng như COVID-19. Việc quản lý các bệnh hoặc tác nhân gây bệnh này\nđòi hỏi phải xác định kịp thời, triển khai các hoạt động kiểm soát nhiễm trùng (ví dụ: báo cáo và chia sẻ thông tin kịp\nthời, cách ly, trang bị bảo hộ cá nhân đặc biệt, đơn vị kiểm soát sinh học) và hành động chuẩn bị cho sức khỏe cộng\nđồng để ngăn ngừa lây truyền trong cộng đồng và gián đoạn xã hội. Các ví dụ về các bệnh truyền nhiễm có hậu quả\nnghiêm trọng hoặc các tác nhân gây bệnh đặc biệt bao gồm hội chứng hô hấp Trung Đông (MERS), hội chứng hô hấp\ncấp tính nặng (SARS), COVID-19, bệnh sởi, bệnh đậu mùa khỉ, bệnh cúm đột biến mới hoặc mới, và bệnh sốt xuất\nhuyết do vi-rút Ebola hoặc các bệnh khác.\n\nĐiều đặc biệt quan trọng là phải giáo dục nhân viên về cách nhận biết sớm, bao gồm cả những nhân viên không làm\nviệc lâm sàng tiếp xúc đầu tiên với bệnh nhân, chẳng hạn như nhân viên đăng ký. Chỉ biết rằng một căn bệnh truyền\nnhiễm có thể đang lây lan là không đủ. Nếu nhân viên không được đào tạo để nhận biết các dấu hiệu và triệu chứng\nvà hành động sớm, mức độ phơi nhiễm và nguy cơ lây lan bệnh nhiễm trùng sẽ tăng lên đáng kể. Việc nhận biết sớm\nđặc biệt quan trọng tại điểm đầu tiên bệnh nhân vào bệnh viện, chẳng hạn như khoa cấp cứu hoặc phòng khám ngoại\ntrú.\n\nMeasurable Elements for PCI.07.02\n1.\nBệnh viện triển khai các giao thức cho các bệnh truyền nhiễm có hậu quả nghiêm trọng hoặc các tác nhân gây bệnh\nđặc biệt, có sẵn để sử dụng tại điểm chăm sóc và giải quyết các vấn đề sau:\n•\nCác thủ tục sàng lọc tại các điểm vào bệnh viện để phát hiện các triệu chứng về đường hô hấp, sốt, phát ban và\ntiền sử đi lại nhằm xác định hoặc bắt đầu đánh giá các bệnh có hậu quả nghiêm trọng hoặc các tác nhân gây\nbệnh đặc biệt. (Xem thêm FMS.09.01, ME 3) Lưu ý: Các điểm vào có thể bao gồm khoa cấp cứu, phòng chăm\nsóc khẩn cấp và phòng khám ngoại trú.\n•\nQuy trình cách ly bệnh nhân\n•\nQuy trình thông báo cho các cơ quan y tế công cộng và nhân viên chủ chốt của bệnh viện\n•\nQuy trình về thiết bị bảo hộ cá nhân bắt buộc và kỹ thuật đeo và tháo đúng cách\n•\nQuy trình kiểm soát nhiễm trùng để hỗ trợ việc cung cấp dịch vụ chăm sóc liên tục và an toàn trong khi bệnh\nnhân đang được cách ly và để giảm thiểu sự tiếp xúc giữa nhân viên, bệnh nhân và khách thăm\n•\nQuy trình quản lý chất thải, vệ sinh và khử trùng không gian, bề mặt và thiết bị chăm sóc bệnh nhân\n2.\nBệnh viện thực hiện giáo dục, đào tạo và đánh giá năng lực cho nhân viên sẽ thực hiện các giao thức đối với các bệnh\ncó hậu quả nghiêm trọng hoặc các mầm bệnh đặc biệt.\n3.\nBệnh viện phối hợp với các dịch vụ vận chuyển và cơ quan y tế công cộng địa phương để thực hiện các tiêu chí và\nquy trình chuyển bệnh nhân đến các cơ sở có mức độ chăm sóc cao hơn.\n4.\nBệnh viện đã xây dựng các chính sách và quy trình bằng văn bản để theo dõi và quản lý nhân viên đã tiếp xúc với tác\nnhân truyền nhiễm có hậu quả nghiêm trọng hoặc mầm bệnh đặc biệt.\n5.\nPhản ứng của bệnh viện đối với các mầm bệnh có tác động nghiêm trọng bao gồm kế hoạch tiêm vắc-xin cho tất cả\nnhân viên, lãnh đạo và bác sĩ khi có thể. (Xem thêm SQE.02.01, ME 2)\n\nCải thiện chất lượng và chương trình giáo dục","m":[]},{"c":"PCI.08.00","ch":"PCI","t":"Quy trình phòng ngừa và kiểm soát nhiễm trùng được tích hợp với chương trình chung của bệnh viện về chất lượng và an toàn cho bệnh nhân, sử dụng dữ liệu và các biện pháp có tầm quan trọng về mặt dịch tễ học đối với bệnh viện.","p":"Việc sử dụng hiệu quả dữ liệu đo lường là rất quan trọng để xác định các ưu tiên và triển khai các chiến lược\ncải thiện hoạt động phòng ngừa và kiểm soát nhiễm trùng nhằm giảm tỷ lệ nhiễm trùng liên quan đến chăm\nsóc sức khỏe xuống mức thấp nhất có thể. Bằng cách tích hợp với chương trình chất lượng bệnh viện và an\ntoàn bệnh nhân nói chung, chương trình phòng ngừa và kiểm soát nhiễm trùng có thể sử dụng cùng một\nphương pháp phân tích và cải tiến dữ liệu, dữ liệu đo lường và thông tin bằng cách hiểu các tỷ lệ và xu hướng\ntương tự ở các bệnh viện tương tự khác và đóng góp dữ liệu vào cơ sở dữ liệu liên quan đến nhiễm trùng.\nTích hợp đầy đủ cho phép tiếp cận nhất quán đối với các cấu trúc cải tiến và giao tiếp với các nhà lãnh đạo và\nhội đồng quản trị.\n\nTất cả các khoa/dịch vụ nên tham gia vào các ưu tiên liên quan đến toàn bệnh viện để đo lường và cũng lựa\nchọn các biện pháp cho các ưu tiên cụ thể của khoa/dịch vụ đối với chương trình phòng ngừa và kiểm soát\nnhiễm trùng. Dữ liệu giám sát bao gồm việc đánh giá chuẩn tỷ lệ nhiễm trùng nội bộ và với các tổ chức\nvà/hoặc cơ sở dữ liệu bên ngoài. Bệnh viện phải xác định một cấu trúc báo cáo chính thức được tích hợp vào\nbộ phận chất lượng và an toàn bệnh nhân. Các dịch vụ hoặc khoa của bệnh viện có cùng rủi ro về nhiễm trùng\nliên quan đến chăm sóc sức khỏe nên hợp tác trong các hoạt động này bằng cách chia sẻ thông tin, phân tích\ndữ liệu và các nỗ lực cải tiến thành công. Ví dụ, các đơn vị chăm sóc đặc biệt có thể có các rủi ro tương tự đối\nvới CLABSI, CAUTI và VAP. Điều quan trọng cần lưu ý là phòng ngừa và kiểm soát nhiễm trùng không phải\nlà động lực chính của các hoạt động này mà là hỗ trợ và tư vấn trong chương trình chất lượng và an toàn bệnh\nnhân nói chung.\n\nCác yếu tố đo lường được của PCI.08.00\n1.\nBệnh viện tích hợp các hoạt động phòng ngừa và kiểm soát nhiễm trùng vào chương trình chất lượng và an\ntoàn bệnh nhân. (Xem thêm GLD.04.00, ME 1; QPS.01.00, ME 1)\n2.\nBệnh viện thu thập và phân tích dữ liệu cho các hoạt động phòng ngừa và kiểm soát nhiễm trùng, bao gồm\ncác bệnh nhiễm trùng quan trọng về mặt dịch tễ học.\n3.\nBệnh viện sử dụng dữ liệu giám sát để đánh giá và hỗ trợ cải thiện chương trình phòng ngừa và kiểm soát\nnhiễm trùng ít nhất một lần một năm. (Xem thêm GLD.04.00, ME 4)\n4.\nDữ liệu giám sát bao gồm tỷ lệ nhiễm trùng chuẩn mực nội bộ và bên ngoài khi áp dụng.\n5.\nChương trình phòng ngừa và kiểm soát nhiễm trùng ghi lại dữ liệu giám sát và cung cấp báo cáo phân tích dữ\nliệu cho các nhà lãnh đạo theo quý","m":[],"sec":"Cải thiện chất lượng và chương trình giáo dục"},{"c":"PCI.08.01","ch":"PCI","t":"Bệnh viện cung cấp giáo dục về các biện pháp phòng ngừa và kiểm soát nhiễm trùng cho nhân viên, chuyên gia chăm sóc sức khỏe, bệnh nhân, gia đình và những người khác khi được chỉ định theo vai trò của họ trong bệnh viện.","p":"Để một bệnh viện có chương trình phòng ngừa và kiểm soát nhiễm trùng hiệu quả, bệnh viện phải giáo dục các nhân\nviên về chương trình khi họ bắt đầu làm việc tại bệnh viện và cung cấp giáo dục liên tục. Nhân viên nên được giáo dục\nvà đào tạo ban đầu và liên tục liên quan đến các xu hướng mới nổi trong phòng ngừa và kiểm soát nhiễm trùng. Chương\ntrình giáo dục bao gồm nhân viên chuyên môn, nhân viên hỗ trợ lâm sàng và phi lâm sàng, bệnh nhân và\ngia đình, thậm chí cả thợ thủ công và những người đến thăm khác. Bệnh nhân và gia đình được khuyến\nkhích tham gia vào việc triển khai và sử dụng các biện pháp phòng ngừa và kiểm soát nhiễm trùng trong\nbệnh viện.\n\nGiáo dục được cung cấp như một phần của định hướng cho tất cả nhân viên mới và được làm mới định\nkỳ, hoặc ít nhất là khi có sự thay đổi trong các chính sách, quy trình và thực hành hướng dẫn chương\ntrình phòng ngừa và kiểm soát nhiễm trùng của bệnh viện, và điều này bao gồm một cơ chế báo cáo với các\nnhà lãnh đạo và hội đồng quản trị.\n\nCác yếu tố đo lường được của PCI.08.01\n1.\nBệnh viện cung cấp giáo dục ban đầu về phòng ngừa và kiểm soát nhiễm trùng cho tất cả nhân viên và bác sĩ khi\nhọ bắt đầu làm việc tại bệnh viện. (Xem thêm SQE.02.00, ME 2; SQE.02.01, ME 5)\n2.\nBệnh viện cung cấp giáo dục và đào tạo liên tục cho tất cả nhân viên liên quan đến chương trình phòng ngừa và\nkiểm soát nhiễm trùng của bệnh viện và các xu hướng mới nổi trong phòng ngừa và kiểm soát nhiễm trùng ít nhất\nmột lần một năm. (Xem thêm SQE.02.01, ME 1)\n3.\nBệnh viện cung cấp giáo dục về phòng ngừa và kiểm soát nhiễm trùng cho bệnh nhân và gia đình.\n4.\nBệnh viện truyền đạt các phát hiện và xu hướng từ các hoạt động của chương trình phòng ngừa và kiểm soát\nnhiễm trùng cho tất cả nhân viên.\n5.\nD Bệnh viện truyền đạt thông tin và dữ liệu từ chương trình phòng ngừa và kiểm soát nhiễm trùng cho các nhà\nlãnh đạo và cơ quan quản lý.\n\nChất lượng và an toàn cho\nbệnh nhân (QPS)\nChất lượng và an toàn\ncho bệnh nhân (QPS)\n\nTổng quan\nTất cả các bệnh viện đều muốn có kết quả điều trị tốt hơn cho bệnh nhân và do đó, họ quan tâm đến việc cải\nthiện tính an toàn và chất lượng chăm sóc, điều trị và dịch vụ mà họ cung cấp. Cách tốt nhất để đạt được dịch\nvụ chăm sóc tốt hơn là trước tiên đo lường hiệu suất của các quy trình hỗ trợ chăm sóc và sau đó sử dụng dữ\nliệu đó để cải thiện. Các tiêu chuẩn trong chương này nhấn mạnh tầm quan trọng của việc sử dụng dữ liệu\ncó ý nghĩa để tạo ra sự thay đổi tích cực.\n\nCác tiêu chuẩn trong chương này đề cập đến các nguyên tắc cơ bản của cải thiện hiệu suất: thu thập và phân\ntích dữ liệu, cải thiện và giám sát hiệu suất. Các nhà lãnh đạo chịu trách nhiệm cuối cùng cho việc cải thiện\nhiệu suất. Họ đặt ra các ưu tiên cải thiện hiệu suất và cung cấp các nguồn lực cần thiết để đạt được sự cải\nthiện. Họ đảm bảo rằng tất cả các cá nhân làm việc trong tổ chức đều tham gia vào các hoạt động cải thiện\nhiệu suất. Trách nhiệm của các nhà lãnh đạo được mô tả đầy đủ hơn trong chương \"Quản trị, Lãnh đạo và\nChỉ đạo\" (GLD). (Các tiêu chuẩn GLD.04.00 đến GLD.04.02 mô tả việc quản lý các hệ thống quan trọng\ntrên toàn bệnh viện hỗ trợ an toàn và chất lượng, cũng như nhu cầu của các nhà lãnh đạo trong việc thiết lập\ncác ưu tiên cải thiện hiệu suất.)\n\nThu thập dữ liệu là nền tảng của việc cải thiện hiệu suất (xem","m":[]},{"c":"QPS.01.00","ch":"QPS","t":"Một hoặc nhiều cá nhân có trình độ sẽ hướng dẫn việc thực hiện chương trình của bệnh viện về chất lượng và an toàn bệnh nhân, đồng thời quản lý các hoạt động cần thiết để thực hiện một chương trình cải tiến chất lượng liên tục và an toàn bệnh nhân hiệu quả trong bệnh viện.","p":"Hiệu quả của chương trình chất lượng bệnh viện và an toàn bệnh nhân phụ thuộc vào những nhà lãnh đạo có\nnăng lực và hiệu quả để thực hiện chương trình. Cơ quan quản lý phê duyệt chương trình và các nhà lãnh đạo\ncung cấp các nguồn lực để thực hiện chương trình. Cần có sự hướng dẫn và quản lý có năng lực để thực hiện\nchương trình nhằm biến cải tiến chất lượng liên tục thành một phần trong cách bệnh viện thực hiện sứ mệnh và\ncác ưu tiên chiến lược của mình. Một hoặc nhiều cá nhân đủ tiêu chuẩn phải giám sát hoạt động của chương\ntrình. Điều này đòi hỏi kiến thức và kinh nghiệm trong nhiều khía cạnh của việc thu thập, tổng hợp, xác thực và\nphân tích dữ liệu, cũng như trong việc thực hiện các cải tiến bền vững.\n\nCá nhân(các cá nhân) giám sát chương trình chất lượng và an toàn bệnh nhân cũng lựa chọn nhân viên chương\ntrình chất lượng và an toàn bệnh nhân có trình độ và năng lực cần thiết cho chương trình.\n\nMột số cá nhân chủ chốt của chương trình chất lượng và an toàn bệnh nhân, chẳng hạn như bác sĩ vô địch hoặc điều\ndưỡng trưởng nhóm chất lượng, có thể làm việc trong một khoa/dịch vụ tại bệnh viện và cần được chương trình\nchất lượng và an toàn bệnh nhân hỗ trợ. Đội ngũ nhân viên chương trình chất lượng và an toàn bệnh nhân cũng\nhiểu cách đưa các ưu tiên của toàn bệnh viện và các ưu tiên cấp khoa/dịch vụ vào một chương trình tổng thể được\nphối hợp. Đội ngũ nhân viên chương trình chất lượng và an toàn bệnh nhân phối hợp và tổ chức các biện pháp trong\ntoàn bệnh viện và hỗ trợ các hoạt động đo lường liên quan đến các ưu tiên của bệnh viện.\n\nĐào tạo và truyền thông là điều cần thiết. Đội ngũ nhân viên chương trình chất lượng và an toàn bệnh nhân giúp hỗ\ntrợ thu thập dữ liệu trong toàn bệnh viện bằng cách hỗ trợ các vấn đề thu thập dữ liệu như tạo biểu mẫu để thu\nthập dữ liệu, xác định dữ liệu nào cần thu thập, cách xác thực dữ liệu và tạo báo cáo. Nhân viên trong toàn bệnh viện\ncó thể cần hỗ trợ trong việc xác thực và phân tích dữ liệu, triển khai các cải tiến và đánh giá xem các cải tiến có được\nduy trì hay không. Do đó, đội ngũ nhân viên chương trình chất lượng và an toàn bệnh nhân liên tục tham gia đào tạo\nvà truyền đạt các vấn đề về chất lượng và an toàn bệnh nhân trong toàn bệnh viện. Bệnh viện phải xác định các tiêu\nchuẩn cần thiết cho đội ngũ nhân viên và lãnh đạo chương trình chất lượng và an toàn bệnh nhân của mình, theo\nluật pháp và quy định, tiêu chuẩn quốc gia của ngành chăm sóc sức khỏe và các yêu cầu hiện hành khác. Ví dụ, bệnh\nviện có thể xác định rằng người đứng đầu chương trình và nhân viên cần có chuyên môn về các phương pháp như\nLean; Six Sigma; Thiết kế, Đo lường, Phân tích, Cải tiến và Kiểm soát (DMAIC); Kế hoạch-Thực hiện-Nghiên cứu-\nHành động / Kế hoạch-Thực hiện-Kiểm tra-Hành động (PDSA/PDCA); và các phương pháp khác, cũng như các yêu\ncầu về bằng cấp tối thiểu, giấy phép hành nghề lâm sàng hoặc kinh nghiệm cụ thể.\n\nCác yếu tố đo lường được của QPS.01.00\n1.\nLãnh đạo bệnh viện lựa chọn một hoặc nhiều cá nhân đủ tiêu chuẩn, có kinh nghiệm về các phương pháp và\nquy trình cải tiến để lãnh đạo việc triển khai chương trình chất lượng và an toàn bệnh nhân của bệnh viện.\n(Xem thêm GLD.06.00, ME 1; GLD.04.00, ME 3; PCI.08.00, ME 1)\n2.\nCá nhân lãnh đạo chương trình chất lượng và an toàn bệnh nhân lựa chọn và giám sát nhân viên đủ tiêu chuẩn\ncho chương trình.\n3.\nChương trình chất lượng và an toàn bệnh nhân hỗ trợ và phối hợp với các trưởng phòng/trưởng dịch vụ để\nthực hiện các biện pháp tương tự trên toàn bệnh viện và để ưu tiên cải tiến của bệnh viện. (Xem thêm\nGLD.04.00, ME 1; QPS.03.03, ME 1)\n4.\nChương trình chất lượng và an toàn bệnh nhân triển khai chương trình đào tạo cho tất cả nhân viên phù hợp\nvới vai trò của các thành viên trong chương trình chất lượng và an toàn bệnh nhân.\n5.\nChương trình chất lượng và an toàn bệnh nhân chịu trách nhiệm truyền đạt thường xuyên về hiệu suất đang\ndiễn ra, kết quả phân tích dữ liệu và kết quả của các nỗ lực cải tiến chất lượng cho tất cả nhân viên.\n6.\nBệnh viện xác định trình độ cho các nhà lãnh đạo chương trình chất lượng và an toàn bệnh nhân và nhân viên\ncủa mình.\n\nĐo lường lựa chọn và thu thập dữ liệu","m":[],"sec":"Quản lý chất lượng và hoạt động an toàn bệnh nhân"},{"c":"QPS.02.00","ch":"QPS","t":"Nhân viên chương trình chất lượng và an toàn bệnh nhân hỗ trợ chỉ số chất lượng và quy trình lựa chọn biện pháp và cung cấp sự phối hợp và tích hợp các hoạt động đo lường trong toàn bệnh viện.","p":"Chỉ số chất lượng và lựa chọn biện pháp là trách nhiệm của ban lãnh đạo, và tất cả các phòng ban và dịch\nvụ—lâm sàng và quản lý—lựa chọn các biện pháp liên quan đến ưu tiên của họ, theo luật và quy định hiện\nhành, tiêu chuẩn ngành chăm sóc sức khỏe quốc gia hoặc các yêu cầu khác như yêu cầu của các công ty bảo\nhiểm chăm sóc sức khỏe. Chương trình chất lượng và an toàn bệnh nhân được mô tả trong các tiêu chuẩn\nQPS này đóng vai trò quan trọng trong việc giúp\n\ncác khoa/dịch vụ này thống nhất về một phương pháp đo lường chung và tạo điều kiện thuận lợi cho việc thu\nthập dữ liệu của các biện pháp đã chọn. Bệnh viện nên phân biệt giữa các biện pháp và chỉ số, vì mỗi biện pháp\nđều có cách sử dụng phù hợp. Các biện pháp bao gồm dữ liệu có thể định lượng. Các chỉ số là các biện pháp\ngián tiếp cung cấp thông tin về các chiều của chất lượng chăm sóc, chẳng hạn như liệu việc chăm sóc có an toàn,\nhiệu quả, lấy bệnh nhân làm trung tâm, kịp thời, hiệu quả, công bằng, chấp nhận được và/hoặc dễ tiếp cận hay\nkhông.\n\nLãnh đạo bệnh viện quyết định các lĩnh vực ưu tiên để đo lường cho toàn bộ bệnh viện và quy trình lựa chọn đo lường\ncho từng khoa/dịch vụ. Có thể dự đoán rằng tại các bệnh viện lớn, có một số cơ hội để lựa chọn các biện pháp tương tự\nở nhiều khoa. Ví dụ, khoa dược, khoa phòng ngừa và kiểm soát nhiễm trùng và khoa/dịch vụ bệnh truyền nhiễm có thể\nđặt ra các ưu tiên liên quan đến việc giảm sử dụng thuốc kháng khuẩn trong bệnh viện. Chương trình chất lượng và an\ntoàn bệnh nhân có thể tích hợp tất cả các hoạt động đo lường trong bệnh viện, bao gồm đo lường văn hóa an toàn và hệ\nthống báo cáo sự kiện bất lợi. Việc tích hợp tất cả các hệ thống đo lường này sẽ tạo cơ hội cho các giải pháp và cải tiến\ntích hợp. Bệnh viện cũng nên xác định các chỉ số hiệu suất, bao gồm các chỉ số hiệu suất chính/chỉ số ưu tiên cao, giải\nquyết các khía cạnh như lĩnh vực chất lượng chăm sóc về an toàn, hiệu quả, lấy bệnh nhân làm trung tâm, tính kịp thời,\nhiệu quả, công bằng và khả năng tiếp cận.\n\nCác yếu tố đo lường được của QPS.02.00\n1.\nChương trình chất lượng và an toàn bệnh nhân tích hợp và hỗ trợ việc lựa chọn các biện pháp và chỉ số\ntrong toàn bệnh viện, ở cấp độ toàn bệnh viện và ở cấp độ khoa hoặc dịch vụ.\n2.\nChương trình chất lượng và an toàn bệnh nhân cung cấp sự phối hợp và tích hợp tất cả các hoạt động\nđo lường cụ thể của khoa và dịch vụ trong toàn bệnh viện. (Xem thêm GLD.04.00, ME 2)\n3.\nChương trình chất lượng và an toàn bệnh nhân tích hợp các hệ thống báo cáo sự kiện an toàn bệnh\nnhân, các biện pháp văn hóa an toàn, các chỉ số chất lượng và các biện pháp khác để tạo điều kiện cho\ncác giải pháp và cải tiến tích hợp. (Xem thêm GLD.04.01, ME 2)\n4.\nChương trình chất lượng và an toàn bệnh nhân theo dõi tiến độ thu thập dữ liệu đo lường và các chỉ số\nchất lượng theo kế hoạch cho các ưu tiên đã chọn.\n\nPhân tích và xác thực dữ liệu đo lường","m":[],"sec":"Đo lường lựa chọn và thu thập dữ liệu"},{"c":"QPS.03.00","ch":"QPS","t":"Chương trình chất lượng và an toàn bệnh nhân bao gồm việc thu thập, tổng hợp và phân tích dữ liệu để hỗ trợ chăm sóc, điều trị và dịch vụ cho bệnh nhân; quản lý bệnh viện; chương trình cải tiến chất lượng liên tục; và tham gia vào các cơ sở dữ liệu bên ngoài.","p":"Bệnh viện có nhiều khả năng đạt được mục tiêu về an toàn và chất lượng hơn khi các quyết định được thúc đẩy bởi\ndữ liệu hợp lệ. Các bệnh viện thành công tổng hợp (biên soạn) dữ liệu hiệu suất từ nhiều nguồn. Bao gồm nhưng\nkhông giới hạn ở những nguồn sau:\n•\nHồ sơ bệnh án của bệnh nhân (ví dụ: tiền sử bệnh, thông tin nhân khẩu học, triệu chứng, tiền sử điều trị,\nlối sống, tiền sử di truyền hoặc gia đình, tài liệu của bác sĩ chăm sóc sức khỏe về việc chăm sóc, điều trị, dịch\nvụ)\n•\nHệ thống quản lý rủi ro và báo cáo sự cố (ví dụ: lỗi dùng thuốc, bệnh nhân bị ngã, lỗi y khoa, sai lệch trong\nchăm sóc)\n•\nQuản lý việc sử dụng (ví dụ: sử dụng sản phẩm máu)\n•\nQuản lý cơ sở vật chất (ví dụ: bảo trì định kỳ thiết bị y tế, nhiệt độ và độ ẩm trong phòng phẫu thuật, kiểm\ntra hệ thống chữa cháy, các vấn đề về an toàn và an ninh như diễn tập phòng cháy)\n•\nChương trình phòng ngừa và kiểm soát nhiễm trùng (ví dụ: tỷ lệ nhiễm trùng sau phẫu thuật, tỷ lệ nhiễm\ntrùng đường tiết niệu liên quan đến ống thông, nhiễm trùng mắc phải tại bệnh viện, tuân thủ vệ sinh tay)\n\n•\nKết quả khảo sát mức độ hài lòng của bệnh nhân, khảo sát văn hóa an toàn của nhân viên và các lĩnh vực khác\nliên quan đến an toàn và chất lượng chăm sóc\n•\nTất cả các khoa và chương trình khác của bệnh viện, vì tất cả những khoa và chương trình này đều phải được\ntích hợp vào chương trình chất lượng và an toàn bệnh nhân tổng thể.\n\nViệc phân tích dữ liệu hiệu suất là rất quan trọng để xác định bệnh viện đang hoạt động tốt ở đâu và cần cải thiện\nở đâu. Chỉ thu thập dữ liệu thôi là không đủ. Khi dữ liệu được phân tích và chuyển thành thông tin, quy trình này\ngiúp bệnh viện thấy được các mô hình và xu hướng cũng như hiểu được lý do cho hiệu suất của họ. Nhiều loại\ndữ liệu được sử dụng để đánh giá hiệu suất của các sáng kiến về an toàn và chất lượng. Điều này phải bao gồm dữ\nliệu chỉ số hiệu suất và dữ liệu kết quả.\n\nChương trình chất lượng và an toàn bệnh nhân xác định, thu thập, tổng hợp và phân tích dữ liệu để hỗ trợ chăm\nsóc bệnh nhân, điều trị và dịch vụ cũng như quản lý bệnh viện. Bệnh viện phải xác định phương pháp thu thập và\ntổng hợp dữ liệu dựa trên loại hồ sơ được sử dụng, chẳng hạn như hồ sơ giấy hoặc hồ sơ điện tử, và bản chất dữ\nliệu được thu thập theo luật và quy định, tiêu chuẩn quốc gia của ngành chăm sóc sức khỏe và mục tiêu hiệu suất\ncủa bệnh viện. Tất cả các khoa và dịch vụ của bệnh viện phải được tích hợp vào chương trình. Phân tích dữ liệu\ntổng hợp cung cấp hồ sơ về hiệu suất của bệnh viện theo thời gian và cho phép so sánh hiệu suất của bệnh viện với\ncác bệnh viện khác, đặc biệt là về các biện pháp toàn bệnh viện do các nhà lãnh đạo lựa chọn. Dữ liệu tổng hợp là\nmột phần quan trọng trong các hoạt động cải thiện hiệu suất của bệnh viện để giúp bệnh viện hiểu được hiệu suất\nhiện tại của mình và xác định các cơ hội cải thiện.\n\nBằng cách tham gia vào các cơ sở dữ liệu bên ngoài, bệnh viện có thể so sánh mình với các bệnh viện tương tự khác\ntrong nước, quốc gia và quốc tế. So sánh là một công cụ hiệu quả để xác định các cơ hội cải thiện và ghi lại mức\nhiệu suất của bệnh viện. Các mạng lưới chăm sóc sức khỏe và những bên mua hoặc thanh toán cho dịch vụ chăm\nsóc sức khỏe thường yêu cầu thông tin như vậy. Các cơ sở dữ liệu bên ngoài rất khác nhau, từ cơ sở dữ liệu bảo\nhiểm đến cơ sở dữ liệu do các hiệp hội chuyên nghiệp duy trì. Các bệnh viện có thể được yêu cầu theo luật hoặc\nquy định phải đóng góp vào các cơ sở dữ liệu bên ngoài. Trong mọi trường hợp, tính bảo mật và tính bí mật của\ndữ liệu và thông tin phải được duy trì.\n\nCác yếu tố đo lường được của QPS.03.00\n1.\nChương trình chất lượng và an toàn bệnh nhân có quy trình tổng hợp dữ liệu từ nhiều nguồn.\n2.\nDữ liệu và thông tin tổng hợp hỗ trợ chăm sóc, điều trị và dịch vụ cho bệnh nhân; quản lý bệnh viện; đánh giá\nhoạt động chuyên môn; và chương trình chất lượng và an toàn bệnh nhân nói chung. (Xem thêm PCC.02.02, ME\n2; QPS.03.02, ME 1)\n3.\nBệnh viện cung cấp dữ liệu và thông tin tổng hợp cho các cơ quan bên ngoài bệnh viện khi luật pháp và quy định\nyêu cầu.\n4.\nBệnh viện triển khai quy trình đóng góp và học hỏi từ các cơ sở dữ liệu bên ngoài để so sánh.\n5.\nBệnh viện duy trì tính bảo mật và bí mật khi đóng góp hoặc sử dụng các cơ sở dữ liệu bên ngoài.","m":[],"sec":"Phân tích và xác thực dữ liệu đo lường"},{"c":"QPS.03.01","ch":"QPS","t":"Bệnh viện sử dụng một quy trình thống kê đã được thiết lập để xác thực dữ liệu như một thành phần của chương trình chất lượng và an toàn bệnh nhân.","p":"Xác thực dữ liệu là một công cụ quan trọng để hiểu chất lượng dữ liệu và để thiết lập mức độ tin cậy mà người\nra quyết định có thể có đối với dữ liệu. Một chương trình cải tiến chất lượng chỉ có giá trị khi dữ liệu được thu\nthập. Nếu dữ liệu bị lỗi, các nỗ lực cải tiến chất lượng sẽ không hiệu quả. Do đó, độ tin cậy và tính hợp lệ của\ncác phép đo là cốt lõi của mọi cải tiến. Để đảm bảo rằng dữ liệu tốt và hữu ích đã được thu thập, cần triển khai\nquy trình xác thực dữ liệu nội bộ. Xác thực dữ liệu trở thành một bước trong việc thiết lập các ưu tiên để đo\nlường, lựa chọn đối tượng cần đo lường, trích xuất hoặc thu thập dữ liệu, phân tích dữ liệu và sử dụng các phát\nhiện để cải tiến.\n\nKhi bệnh viện công bố dữ liệu về kết quả lâm sàng, an toàn cho bệnh nhân hoặc các lĩnh vực khác hoặc theo cách\nkhác công khai dữ liệu, chẳng hạn như trên trang web của bệnh viện, bệnh viện có nghĩa vụ đạo đức phải cung cấp\nthông tin chính xác cho công chúng. Lãnh đạo bệnh viện có trách nhiệm đảm bảo dữ liệu hợp lệ. Dữ liệu phải\nđược xác thực bằng quy trình dựa trên bằng chứng phù hợp với việc thu thập dữ liệu (ví dụ: hồ sơ sức khỏe điện\ntử có xử lý tự động so với hồ sơ giấy yêu cầu khai thác dữ liệu thủ công). Độ tin cậy và tính hợp lệ của phép đo và\nchất lượng dữ liệu có thể được thiết lập thông qua quy trình xác thực dữ liệu nội bộ của bệnh viện hoặc có thể\nđược đánh giá bởi bên thứ ba độc lập, chẳng hạn như một công ty bên ngoài do bệnh viện ký hợp đồng. Các nguồn\nlực như bộ công cụ Đảm bảo chất lượng dữ liệu của Tổ chức Y tế Thế giới là một ví dụ về công cụ hỗ trợ xác\nthực dữ liệu. Quy trình này có thể bao gồm các biện pháp đơn giản để xác thực dữ liệu, chẳng hạn như quy trình\nđánh giá của hai người để đảm bảo độ tin cậy giữa các đánh giá viên.\n\nCác yếu tố đo lường được của QPS.03.01\n1. Bệnh viện xác thực dữ liệu khi bất kỳ điều kiện nào sau đây được ghi nhận, tối thiểu:\n• Một biện pháp mới được triển khai (cụ thể là các biện pháp lâm sàng nhằm giúp\n bệnh viện đánh giá và cải thiện một quy trình hoặc kết quả lâm sàng quan trọng).\n• Dữ liệu sẽ được công khai trên trang web của bệnh viện hoặc theo những cách khác.\n• Một biện pháp hiện có đã có thay đổi, chẳng hạn như phương pháp thu thập dữ liệu đã thay đổi hoặc\nquy trình hoặc người tóm tắt dữ liệu đã thay đổi.\n• Dữ liệu thu được từ một biện pháp hiện có đã thay đổi theo cách không thể giải thích được.\n• Nguồn dữ liệu đã thay đổi, chẳng hạn như khi một phần hồ sơ chăm sóc sức khỏe của bệnh nhân đã\nđược chuyển sang định dạng điện tử và do đó nguồn dữ liệu hiện vừa là điện tử vừa là giấy.\n• Chủ đề thu thập dữ liệu đã thay đổi, chẳng hạn như thay đổi về độ tuổi trung bình của bệnh nhân,\nbệnh đi kèm, thay đổi giao thức nghiên cứu, hướng dẫn thực hành mới được triển khai hoặc công\nnghệ và phương pháp điều trị mới được giới thiệu.\n• Khi phương pháp thu thập dữ liệu là thủ công và nhân viên thu thập dữ liệu đã thay đổi giữa chu kỳ.\n2. Bệnh viện sử dụng phương pháp dựa trên bằng chứng để xác thực dữ liệu.\n3. Lãnh đạo bệnh viện chịu trách nhiệm về tính hợp lệ của dữ liệu chất lượng và kết quả được công bố.","m":[]},{"c":"QPS.03.02","ch":"QPS","t":"Các cá nhân có kinh nghiệm, kiến thức và kỹ năng chuyên môn sẽ tổng hợp, xác thực và phân tích dữ liệu một cách có hệ thống trong bệnh viện.","p":"Cần có chuyên môn chuyên sâu để tổng hợp, phân tích và chuyển đổi dữ liệu thành thông tin hữu ích một cách chính xác.\nTổng hợp và phân tích dữ liệu đòi hỏi những cá nhân đủ tiêu chuẩn đáp ứng các tiêu chí sau:\n•\nHiểu về quản lý thông tin.\n•\nCó kỹ năng về các phương pháp tổng hợp dữ liệu.\n•\nBiết cách sử dụng nhiều công cụ thống kê khác nhau để phân tích dữ liệu.\n\nKết quả phân tích dữ liệu phải được chuyển đổi thành các báo cáo mà những cá nhân chịu trách nhiệm về quy trình hoặc\nkết quả được đo lường có thể dễ dàng hiểu được và có thể hành động dựa trên kết quả. Những cá nhân này có thể là lâm\nsàng, quản lý hoặc kết hợp cả hai. Phân tích dữ liệu cung cấp phản hồi liên tục về thông tin cải tiến chất lượng liên tục\nđể giúp những cá nhân đó đưa ra quyết định và liên tục cải thiện các quy trình lâm sàng và quản lý.\n\nHiểu các kỹ thuật thống kê là rất quan trọng trong phân tích dữ liệu, đặc biệt là trong việc giải thích sự thay đổi và quyết\nđịnh nơi cần cải thiện. Biểu đồ chạy, biểu đồ kiểm soát, biểu đồ histogram và biểu đồ Pareto là những ví dụ về các công\ncụ thống kê hữu ích trong việc hiểu các xu hướng và sự thay đổi trong chăm sóc sức khỏe.\n\nChương trình chất lượng và an toàn bệnh nhân tham gia vào việc xác định tần suất tổng hợp và phân tích dữ liệu. Tần suất\ncủa quy trình này phụ thuộc vào hoạt động hoặc khu vực được đo lường và tần suất đo lường, theo luật pháp và quy định\ncũng như các tiêu chuẩn quốc gia của ngành chăm sóc sức khỏe.\nVí dụ, dữ liệu kiểm soát chất lượng phòng xét nghiệm lâm sàng có thể được tổng hợp và phân tích hàng tuần để đáp ứng các\nquy định của địa phương và dữ liệu bệnh nhân ngã có thể được tổng hợp và phân tích hàng quý nếu tình trạng ngã không\nthường xuyên. Việc tổng hợp và phân tích dữ liệu tại các thời điểm cho phép bệnh viện đánh giá tính ổn định của một quy\ntrình cụ thể hoặc khả năng dự đoán kết quả cụ thể liên quan đến kỳ vọng.\n\nMục tiêu của phân tích dữ liệu là có thể so sánh một bệnh viện theo những cách sau:\n• Với chính bệnh viện theo thời gian, chẳng hạn như tháng này qua tháng khác hoặc năm này qua năm khác\n• Với các bệnh viện tương tự khác, chẳng hạn như thông qua cơ sở dữ liệu tham khảo\n• Với các tiêu chuẩn, chẳng hạn như các tiêu chuẩn do các tổ chức công nhận và chuyên môn đặt ra hoặc các tiêu chuẩn\ndo luật pháp hoặc\n• quy định đặt ra\n• Với các thông lệ mong muốn được công nhận được xác định trong tài liệu là thông lệ tốt nhất hoặc tốt hơn hoặc hướng\ndẫn thực hành\n\nNhững so sánh này giúp bệnh viện hiểu được nguồn gốc và bản chất của sự thay đổi không mong muốn và giúp tập trung\ncác nỗ lực cải thiện.\n\nCác yếu tố đo lường được của QPS.03.02\n1.\nBệnh viện tổng hợp, phân tích và chuyển đổi dữ liệu thành thông tin hữu ích để xác định các cơ hội cải thiện.\n(Xem thêm QPS.03.00, ME 2)\n2.\nBệnh viện xác định và phê duyệt các tiêu chuẩn phù hợp cho những cá nhân tham gia thu thập, tổng hợp, xác\nthực và phân tích dữ liệu.\n3.\nBệnh viện sử dụng các công cụ và kỹ thuật thống kê đã được thiết lập trong quá trình phân tích.\n4.\nLãnh đạo bệnh viện xác định tần suất báo cáo kết quả phân tích cho những người chịu trách nhiệm hành động,\ntheo luật pháp và quy định cũng như các tiêu chuẩn quốc gia của ngành chăm sóc sức khỏe.\n5.\nPhân tích dữ liệu hỗ trợ so sánh nội bộ và bên ngoài theo thời gian, bao gồm so sánh với cơ sở dữ liệu của các\nbệnh viện tương tự, với các thông lệ tốt nhất và với các nguồn chuyên môn khoa học khách quan.","m":[]},{"c":"QPS.03.03","ch":"QPS","t":"Quá trình phân tích dữ liệu bao gồm ít nhất một lần đánh giá tác động về mặt lâm sàng, tài chính và hoạt động của các ưu tiên cải tiến trên toàn bệnh viện mỗi năm.","p":"Phân tích cung cấp thông tin hữu ích về những cải tiến nào tác động tích cực đến kết quả lâm sàng và hiệu quả để biện minh\ncho việc phân bổ nguồn lực. Chương trình chất lượng và an toàn bệnh nhân bao gồm phân tích tác động lâm sàng, tài chính\nvà hoạt động của các cải tiến ưu tiên được các nhà lãnh đạo hỗ trợ. Ví dụ, phân tích cho thấy có bằng chứng hỗ trợ việc sử\ndụng các hướng dẫn thực hành lâm sàng để chuẩn hóa việc chăm sóc, điều trị và dịch vụ có tác động đáng kể đến hiệu quả\nvà giảm thời gian nằm viện, từ đó giảm chi phí. Do đó, các nhà lãnh đạo bệnh viện có thể đưa ra quyết định sáng suốt về việc\nphân bổ nguồn lực cho các sáng kiến cải thiện hiệu suất.\n\nNhóm chương trình chất lượng và an toàn bệnh nhân phải sử dụng các công cụ phù hợp để đánh giá việc sử dụng các nguồn\nlực cho quy trình hiện tại và sau đó đánh giá lại việc sử dụng các nguồn lực cho quy trình được cải thiện. Các nguồn lực có\nthể là con người (ví dụ: thời gian dành cho từng bước trong quy trình) hoặc có thể liên quan đến việc sử dụng công nghệ\nhoặc các nguồn lực khác. Sau đó, đánh giá được báo cáo cho các nhà lãnh đạo và những người khác chịu trách nhiệm đưa ra\nquyết định.\n\nCác yếu tố đo lường được của QPS.03.03\n1.\nBệnh viện thu thập dữ liệu về số lượng và loại nguồn lực được sử dụng cho ít nhất một dự án cải tiến ưu tiên toàn\nbệnh viện mỗi năm trước và sau khi cải tiến. (Xem thêm GLD.04.00, ME 1; QPS.01.00, ME 3)\n2.\nĐội ngũ nhân viên chương trình chất lượng và an toàn bệnh nhân làm việc với các đơn vị khác như nhân sự, công\nnghệ thông tin và tài chính để quyết định dữ liệu nào sẽ được thu thập.\n3.\nBệnh viện sử dụng kết quả phân tích để tinh chỉnh quy trình và báo cáo thông qua cơ chế chương trình chất lượng\nvà an toàn bệnh nhân cho các nhà lãnh đạo.","m":[]},{"c":"QPS.03.04","ch":"QPS","t":"Bệnh viện xác định các xu hướng và biến động không mong muốn và luôn tiến hành phân tích chuyên sâu hoặc phân tích hệ thống toàn diện khi phát hiện ra những điều này từ dữ liệu thu thập được.","p":"Phải có một cấu trúc và quy trình chính thức để thu thập dữ liệu toàn diện về nhiều lĩnh vực chăm sóc, điều trị và dịch vụ\nbệnh nhân; xác định và phân tích chuyên sâu các xu hướng không mong muốn; và báo cáo kết quả cho cơ quan quản lý như\nmột phần của chương trình chất lượng và an toàn bệnh nhân. Việc thu thập dữ liệu phải đủ để phát hiện các xu hướng và\nmô hình và sẽ thay đổi tùy thuộc vào tần suất dịch vụ và/hoặc rủi ro đối với bệnh nhân. Dữ liệu phải bao gồm tất cả các\nkhoa và dịch vụ của bệnh viện.\n\nBệnh viện xác định phạm vi thu thập dữ liệu để xác định các rủi ro về an toàn bệnh nhân trong toàn bệnh viện dựa trên\ndịch vụ chăm sóc, điều trị và các dịch vụ mà bệnh viện cung cấp, và theo các tiêu chuẩn, luật và quy định của ngành chăm\nsóc sức khỏe hoặc quốc gia, các yêu cầu báo cáo bên ngoài và các lĩnh vực quan tâm khác đã xác định. Điều này cũng bao\ngồm các nỗ lực khuyến khích nhân viên và bác sĩ chăm sóc sức khỏe báo cáo sự cố hoặc sai lệch vì bệnh viện không thể xác\nđịnh rủi ro để cải thiện nếu không có thông tin có giá trị này. Bệnh viện phải có khả năng xác định các xu hướng xuống\ntừng đơn vị chăm sóc bệnh nhân hoặc cấp độ dịch vụ cụ thể và phải chứng minh rằng tất cả các khoa và dịch vụ đều được\ntích hợp vào chương trình chất lượng và an toàn bệnh nhân.\n\nBệnh viện nên kết hợp việc sử dụng các khuôn khổ như Văn hóa công bằng hoặc các khái niệm tương tự giúp giảm thiểu\nviệc đổ lỗi khi giải quyết các lỗi hoặc sai lệch mà nhân viên trực tiếp tham gia. Bệnh viện cũng phải sử dụng phương pháp\ncó cấu trúc, chẳng hạn như phân tích nguyên nhân gốc rễ, trong các quy trình phân tích hệ thống toàn diện của mình.\n\nCác yếu tố đo lường được của QPS.03.04\n1.\nBệnh viện thực hiện các quy trình thu thập dữ liệu để đảm bảo xác định được các rủi ro đối với sự an toàn của\nbệnh nhân.\n2.\nBệnh viện tiến hành phân tích chuyên sâu hoặc phân tích hệ thống toàn diện dữ liệu khi xảy ra các sự kiện bất lợi,\nmô hình hoặc xu hướng không mong muốn.\n3.\nBệnh viện thực hiện thu thập và phân tích dữ liệu cho tất cả các trường hợp sau, tối thiểu là khi áp dụng:\n• Tất cả các phản ứng truyền máu đã được xác nhận\n• Tất cả các phản ứng thuốc nghiêm trọng hoặc các sự kiện an toàn của bệnh nhân liên quan đến thuốc theo\nđịnh nghĩa của bệnh viện hoặc luật và quy định\n• Tất cả các lỗi dùng thuốc và các trường hợp suýt xảy ra, theo định nghĩa của bệnh viện (Xem thêm\nMMU.07.01, ME 2)\n• Tất cả các sự kiện hoặc lỗi an toàn của bệnh nhân lớn liên quan đến các thủ thuật phẫu thuật\n• Tất cả các sự khác biệt lớn giữa chẩn đoán trước phẫu thuật và sau phẫu thuật; ví dụ, chẩn đoán trước phẫu\nthuật về tắc ruột và chẩn đoán sau phẫu thuật về phình động mạch chủ bụng vỡ (AAA)\n• Các sự kiện hoặc mô hình sự kiện về an toàn bệnh nhân trong quá trình gây mê thủ thuật bất kể đường dùng\n• Các sự kiện hoặc mô hình sự kiện về an toàn bệnh nhân trong quá trình gây mê bất kể đường dùng\n• Các sự kiện hoặc lỗi về an toàn bệnh nhân liên quan đến nhận dạng bệnh nhân\n• Các sự kiện hoặc lỗi về an toàn bệnh nhân liên quan đến mẫu bệnh lý, chẳng hạn như sinh thiết hoặc các\nmẫu mô khác (Xem thêm AOP.04.00, ME 6)\n4.\nBệnh viện sử dụng kết quả phân tích để thực hiện các hành động cải thiện chất lượng và tính an toàn của dịch\nvụ, phương pháp điều trị hoặc chức năng.\n5.\nBệnh viện báo cáo dữ liệu về các rủi ro đã xác định đối với an toàn bệnh nhân cho cơ quan quản lý như một phần\ncủa chương trình chất lượng và an toàn bệnh nhân.\n6.\nBệnh viện thực hiện các biện pháp được thiết kế để khuyến khích nhân viên bệnh viện báo cáo sự cố về an toàn\nbệnh nhân.\n\nĐạt được và duy trì sự cải thiện","m":[]},{"c":"QPS.04.00","ch":"QPS","t":"Bệnh viện đạt được và duy trì sự cải thiện về chất lượng và an toàn.","p":"Thông tin từ phân tích dữ liệu hữu ích để xác định những cải tiến tiềm năng hoặc để giảm (hoặc ngăn ngừa) các sự cố an\ntoàn cho bệnh nhân và là một yếu tố quan trọng của các chương trình chất lượng bệnh viện và an toàn cho bệnh nhân. Dữ\nliệu đo lường thường quy, cũng như dữ liệu từ các phân tích chuyên sâu, góp phần vào việc hiểu được nơi cần cải thiện\nvà cách ưu tiên các nỗ lực cải thiện. Các cải tiến được lên kế hoạch cho các lĩnh vực thu thập dữ liệu ưu tiên do các nhà\nlãnh đạo bệnh viện xác định.\n\nSau khi một hoặc nhiều cải tiến được lên kế hoạch, dữ liệu được thu thập trong thời gian thử nghiệm để chứng minh\nrằng thay đổi theo kế hoạch thực sự là một cải tiến. Để đảm bảo rằng cải tiến được duy trì, dữ liệu đo lường sau đó được\nthu thập để phân tích liên tục. Những thay đổi hiệu quả được đưa vào các quy trình vận hành tiêu chuẩn và bất kỳ chương\ntrình đào tạo nhân viên nào cần thiết đều được thực hiện. Bệnh viện ghi lại những cải tiến đã đạt được và duy trì như\nmột phần của chương trình cải tiến chất lượng liên tục của mình. Bệnh viện nên đánh giá lại các mục tiêu theo các khoảng\nthời gian xác định cho đến khi đạt được và duy trì được mục tiêu thành công, và liệu có nên hủy bỏ mục tiêu đó để chuyển\nsang xác định trọng tâm mới cho cải tiến hay không.\n\nCác yếu tố đo lường được của QPS.04.00\n1.\nBệnh viện lập kế hoạch, thử nghiệm và triển khai các cải tiến về chất lượng và an toàn cho bệnh nhân. (Xem\nthêm GLD.04.02, ME 1)\n2.\nCó dữ liệu để chứng minh rằng các cải tiến có hiệu quả và bền vững. (Xem thêm GLD.06.01, ME 3)\n3.\nBệnh viện thực hiện các thay đổi chính sách khi cần thiết để lập kế hoạch, thực hiện và duy trì cải tiến.\n4.\nCác cải tiến thành công được ghi chép và xem xét bởi chương trình chất lượng và an toàn cho bệnh nhân và\ncác nhà lãnh đạo bệnh viện để hiểu lý do tại sao các nỗ lực thành công hoặc không thành công. (Xem thêm\nGLD.04.00, ME 2)","m":[],"sec":"Đạt được và duy trì sự cải thiện"}];})(window);
